INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q31', 'behavior-support', 'aba', 'fill_in', 'DRL(낮은 비율의 차별강화)에서 반응간 시간(IRT) 기반 DRL을 적용할 때, 학생이 수업 중 질문 행동을 1시간에 20회 보이고 있다. 목표를 1시간에 10회로 줄이려면, IRT 타이머를 최소 ( )분으로 설정해야 한다.', NULL, NULL, '6', 'IRT 기반 DRL에서 타이머 설정은 ''목표 시간 ÷ 목표 반응 수''로 계산합니다. 60분 ÷ 10회 = 6분. 즉, 이전 반응 후 최소 6분이 경과한 뒤에 나타난 반응만 강화합니다. DRL은 행동을 완전히 제거하지 않고 적절한 수준으로 감소시킬 때 사용합니다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q32', 'behavior-support', 'strategies', 'descriptive', '자기교수법(self-instruction)의 5단계를 순서대로 나열하고, 각 단계에서 교사와 학생의 역할을 설명하시오.', '초등학교 특수학급의 박 교사는 ADHD 학생에게 수학 문장제 풀이 시 자기교수법을 적용하려 한다. 학생은 문제를 읽지 않고 바로 숫자만 보고 연산하는 경향이 있다.', NULL, '[모범 답안]
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q33', 'behavior-support', 'assessment', 'ox', '기초선 자료 수집 시, 자료의 경향이 불안정하더라도 최소 3회 이상 측정하였다면 중재를 시작해도 된다.', NULL, NULL, 'X', '기초선 자료는 안정적 경향(stable trend)을 보일 때까지 수집해야 합니다. 단순히 측정 횟수가 아니라, 자료의 수준(level)과 경향(trend)이 안정적이어야 중재 효과를 비교할 수 있는 기준점이 됩니다. 불안정한 기초선에서 중재를 시작하면 행동 변화가 중재 때문인지 자연적 변동인지 판단할 수 없습니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q34', 'behavior-support', 'strategies', 'fill_in', '토큰경제의 구성요소 3가지는 ( ㉠ ), ( ㉡ ), ( ㉢ )이다. ㉠은 목표행동 수행 시 즉시 제공되는 조건강화제이고, ㉡은 토큰과 교환할 수 있는 활동이나 물건이며, ㉢은 토큰과 후원강화제의 교환 기준이다.', NULL, NULL, '토큰(token) / 후원강화제(backup reinforcer) / 교환비율(exchange rate)', '토큰경제는 ①토큰(조건강화제로서 즉각 제공), ②후원강화제(토큰으로 교환 가능한 실제 강화제), ③교환비율(몇 개의 토큰으로 후원강화제를 교환하는지)로 구성됩니다. 토큰은 일반화된 조건강화제로 기능하며, 포만(satiation)에 대한 저항력이 높다는 장점이 있습니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q35', 'behavior-support', 'aba', 'multiple', '촉진(prompting) 위계에서 ''최소 촉진법(least-to-most prompting)''의 올바른 순서는?', NULL, ARRAY['신체적 촉진 → 모델링 → 언어적 촉진 → 제스처 촉진 → 자연적 단서', '자연적 단서 → 언어적 촉진 → 제스처 촉진 → 모델링 → 신체적 촉진', '자연적 단서 → 제스처 촉진 → 언어적 촉진 → 모델링 → 신체적 촉진', '신체적 촉진 → 제스처 촉진 → 모델링 → 언어적 촉진 → 자연적 단서']::text[], '1', '최소 촉진법은 가장 적은 도움에서 시작하여 점차 강한 촉진으로 이동합니다. 자연적 단서 → 언어적 촉진 → 제스처 촉진 → 모델링 → 신체적 촉진 순서입니다. 이는 학습자의 독립성을 최대화하기 위한 전략으로, 학생이 최소한의 도움으로 반응할 기회를 먼저 제공합니다.', '{"0": "이것은 최대 촉진법(most-to-least)의 순서입니다.", "2": "언어적 촉진과 제스처 촉진의 순서가 뒤바뀌었습니다. 언어적 촉진이 제스처보다 덜 침습적입니다.", "3": "이것은 최대 촉진법의 순서이며, 언어적 촉진과 모델링의 위치도 정확하지 않습니다."}'::jsonb, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q36', 'behavior-support', 'strategies', 'fill_in', '과제분석 후 교수법 중, 과제의 마지막 단계부터 먼저 가르치고 나머지 단계는 교사가 수행해 주는 방법을 ( ㉠ )이라 하고, 모든 단계를 매 시행마다 연습하되 독립적으로 수행하지 못하는 단계에서 촉진을 제공하는 방법을 ( ㉡ )이라 한다.', NULL, NULL, '후진연쇄법(backward chaining) / 총과제제시법(total task presentation)', '연쇄법에는 전진연쇄(첫 단계부터 순서대로), 후진연쇄(마지막 단계부터 역순으로), 총과제제시법(모든 단계를 매 시행마다 연습)이 있습니다. 후진연쇄는 과제 완성의 성취감을 빨리 경험하게 해주고, 총과제제시법은 과제의 전체 흐름을 매번 경험하게 해주는 장점이 있습니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('bs-q37', 'behavior-support', 'aba', 'descriptive', '간헐강화 스케줄 4가지(FR, VR, FI, VI)를 비교하여 설명하고, 각 스케줄의 반응 패턴 특성을 서술하시오.', NULL, NULL, '[모범 답안]
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q31', 'curriculum', 'theory', 'fill_in', '2022 개정 특수교육 교육과정에서 초등학교 1~2학년은 ( ㉠ ) 교육과정, 고등학교 학생이 기본교육과정을 적용받을 경우 ( ㉡ ) 교육과정을 편성하며, 기본교육과정의 교과는 교과(군)별로 수업 시수의 ( ㉢ )% 범위 내에서 시수를 증감할 수 있다.', NULL, NULL, '공통 / 기본 / 20', '2022 개정 교육과정에서 초1~2는 공통교육과정, 초3~고교는 공통·선택중심·기본교육과정 중 선택 가능합니다. 기본교육과정은 특수교육대상자를 위한 것으로, 교과(군)별 20% 범위 내 시수 증감이 가능하며, 이는 학생의 장애 특성과 요구에 맞춘 유연한 편성을 위함입니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q32', 'curriculum', 'planning', 'multiple', '다음 중 2022 개정 교육과정에서 제시하는 ''범교과 학습 주제''에 해당하지 않는 것은?', NULL, ARRAY['안전·건강 교육', '인성 교육', '경제·금융 교육', '직업재활 교육']::text[], '3', '2022 개정 교육과정의 범교과 학습 주제에는 안전·건강, 인성, 진로, 민주시민, 인권, 다문화, 통일, 독도, 경제·금융, 환경·지속가능발전 등이 포함됩니다. ''직업재활 교육''은 범교과 학습 주제가 아니라 특수교육 전환교육 영역에 해당합니다.', '{"0": "안전·건강 교육은 범교과 학습 주제에 포함됩니다.", "1": "인성 교육은 범교과 학습 주제에 포함됩니다.", "2": "경제·금융 교육은 2022 개정에서 새롭게 강조된 범교과 학습 주제입니다."}'::jsonb, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q33', 'curriculum', 'theory', 'descriptive', '컴퓨터 보조 수업(CAI)의 5가지 유형을 제시하고, 각 유형의 특징과 적합한 학습 장면을 설명하시오.', '특수학교 교사 이 모씨는 지적장애 학생들에게 수학 교과를 지도하기 위해 CAI를 활용하고자 한다.', NULL, '[모범 답안]
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q34', 'curriculum', 'planning', 'fill_in', '보편적 학습설계(UDL)의 3가지 원리는 다양한 ( ㉠ ) 수단의 제공, 다양한 ( ㉡ ) 수단의 제공, 다양한 ( ㉢ ) 수단의 제공이다.', NULL, NULL, '표상(representation) / 행동과 표현(action and expression) / 참여(engagement)', 'UDL(Universal Design for Learning)은 CAST에서 개발한 교육과정 설계 원리로, ①표상(정보 제시 방법의 다양화 - What), ②행동과 표현(학습 결과 표현 방법의 다양화 - How), ③참여(학습 동기 유발 방법의 다양화 - Why)의 3원리로 구성됩니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q35', 'curriculum', 'planning', 'ox', '교수적 수정(instructional modification)의 4요소는 교수환경, 교수방법, 교수내용, 평가방법이며, 이 중 교수내용 수정은 교육과정 자체를 변경하는 것이므로 통합학급에서는 적용할 수 없다.', NULL, NULL, 'X', '교수적 수정의 4요소(교수환경, 교수방법, 교수내용, 평가방법)는 모두 통합학급에서 적용 가능합니다. 교수내용 수정은 교육과정 자체의 변경이 아니라, 학습량 조절, 내용의 난이도 조절, 대안적 교육과정 활용 등을 통해 동일한 교육과정 내에서 학생의 수준에 맞게 내용을 조정하는 것입니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q36', 'curriculum', 'theory', 'descriptive', '스키마 기반 교수(SBI)의 절차를 단계별로 설명하고, 학습장애 학생의 수학 문장제 해결에 SBI가 효과적인 이유를 서술하시오.', '학습장애 학생 민수는 수학 연산 능력은 보통 수준이나, 문장제 문제에서 어떤 연산을 적용해야 하는지 파악하지 못하여 정답률이 매우 낮다.', NULL, '[모범 답안]
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cur-q37', 'curriculum', 'evaluation', 'fill_in', 'RAP 전략은 읽기 이해 전략으로, R은 ( ㉠ ), A는 ( ㉡ ), P는 ( ㉢ )을 의미한다. 이 전략은 ( ㉣ ) 장애 학생의 읽기 이해력 향상에 효과적이다.', NULL, NULL, 'Read(읽기) / Ask(질문하기) / Paraphrase(자기 말로 바꾸기) / 학습', 'RAP 전략은 Schumaker 등이 개발한 읽기 이해 전략으로, Read(단락 읽기) → Ask(주요 아이디어와 세부사항에 대해 자문하기) → Paraphrase(자기 말로 바꾸어 표현하기)의 3단계로 구성됩니다. 학습장애 학생의 읽기 이해, 특히 의미 파악과 정보 재구성 능력 향상에 효과적인 학습전략교수(learning strategy instruction)의 대표적 예입니다.', NULL, 2, 'KICE 기출 기반', '{"disability": "학습장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('inc-q31', 'inclusive-education', 'practices', 'descriptive', '협력교수(co-teaching)의 6가지 유형을 제시하고, 각 유형의 특징과 적용 상황을 설명하시오.', '통합학급 운영 시 일반교사와 특수교사가 협력교수를 실시하려 한다. 학급에는 학습장애 학생 2명, 지적장애 학생 1명이 통합되어 있다.', NULL, '[모범 답안]
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('inc-q32', 'inclusive-education', 'strategies', 'fill_in', '학급전체또래교수(CWPT)에서 학급을 두 팀으로 나누어 ( ㉠ ) 역할을 교대로 수행하며, 또래중재학습전략(PALS)은 ( ㉡ ) 수준의 학생과 ( ㉢ ) 수준의 학생을 짝지어 구조화된 활동을 수행한다.', NULL, NULL, '교수자-학습자(tutor-tutee) / 상위 / 하위', 'CWPT(Classwide Peer Tutoring)는 Greenwood 등이 개발한 방법으로, 학급 전체가 교수자-학습자 역할을 교대하며 팀 경쟁 요소를 포함합니다. PALS(Peer-Assisted Learning Strategies)는 Fuchs 등이 개발하였으며, 상위 수준과 하위 수준의 학생을 짝지어 구조화된 읽기/수학 활동을 수행합니다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('inc-q33', 'inclusive-education', 'theory', 'fill_in', '자폐성장애의 인지적 특성 중, 세부 정보 처리에는 강하나 전체적 맥락이나 의미를 통합하는 데 어려움을 보이는 특성을 ( )이라 한다.', NULL, NULL, '약한 중심통합(weak central coherence)', '약한 중심통합(weak central coherence)은 Frith(1989)가 제안한 자폐성장애의 인지 이론으로, 정보를 전체적 맥락에서 통합하기보다 부분적·세부적으로 처리하는 경향을 설명합니다. 이로 인해 퍼즐 맞추기나 숨은그림찾기에는 뛰어나지만, 이야기의 주제 파악이나 사회적 맥락 이해에는 어려움을 보입니다.', NULL, 2, 'KICE 기출 기반', '{"disability": "자폐성장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('inc-q34', 'inclusive-education', 'theory', 'multiple', '자기결정(self-determination)의 4가지 본질적 특성에 해당하지 않는 것은?', NULL, ARRAY['자율성(autonomy)', '자기조절(self-regulation)', '자기효능감(self-efficacy)', '심리적 역량강화(psychological empowerment)']::text[], '2', 'Wehmeyer가 제시한 자기결정의 4가지 본질적 특성은 자율성(autonomy), 자기조절(self-regulation), 심리적 역량강화(psychological empowerment), 자기실현(self-realization)입니다. 자기효능감은 Bandura의 사회학습이론 개념으로 자기결정의 본질적 특성에는 포함되지 않습니다.', '{"0": "자율성은 자기결정의 4가지 본질적 특성 중 하나입니다.", "1": "자기조절은 자기결정의 4가지 본질적 특성 중 하나입니다.", "3": "심리적 역량강화는 자기결정의 4가지 본질적 특성 중 하나입니다."}'::jsonb, 1, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('inc-q35', 'inclusive-education', 'strategies', 'ox', '긍정적 행동지원(PBS)의 3단계 모형에서 1단계(보편적 지원)는 전체 학생의 약 80%를 대상으로 하며, 3단계(개별적 지원)는 약 5%의 학생에게 집중적으로 적용된다.', NULL, NULL, 'O', 'PBS의 3단계(RTI와 동일 구조) 모형에서 1단계(보편적/전체) 지원은 전체 학생의 약 80%에게 적용되는 예방적 차원이고, 2단계(소그룹/표적) 지원은 약 15%의 위험군 학생, 3단계(개별적/집중) 지원은 약 5%의 고위험 학생에게 개별화된 집중 지원을 제공합니다.', NULL, 1, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('inc-q36', 'inclusive-education', 'practices', 'descriptive', '전환교육(transition education)에서 ''자기옹호(self-advocacy)''의 개념을 설명하고, 지역사회 기반 교수(community-based instruction)가 전환교육에서 중요한 이유를 서술하시오.', '고등학교 특수학급의 최 교사는 졸업을 앞둔 지적장애 학생의 전환교육 계획을 수립하고 있다. 학생은 지역사회 내 카페에서 바리스타로 취업하기를 희망하고 있다.', NULL, '[모범 답안]
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q1', 'communication-disorder', 'articulation', 'fill_in', '조음오류의 4가지 유형은 대치(substitution), 생략(omission), ______, 첨가(addition)이다.', NULL, NULL, '왜곡(distortion)', '조음오류의 4가지 유형은 대치, 생략, 왜곡, 첨가이다. 왜곡은 목표 음소와 유사하지만 정확하지 않은 소리를 산출하는 오류로, 목표 음소가 해당 언어의 음소 목록에 없는 소리로 대체될 때 발생한다.', NULL, 1, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q2', 'communication-disorder', 'articulation', 'multiple', '아동이 /사과/를 [타과]로 발음했다. 이 조음오류 유형은?', NULL, ARRAY['대치', '생략', '왜곡', '첨가']::text[], '대치', '대치(substitution)는 목표 음소를 해당 언어의 다른 음소로 바꾸어 산출하는 오류이다. /ㅅ/→[ㅌ]는 한국어 음소 /ㅌ/로 대체한 것이므로 대치에 해당한다.', '{"생략": "생략은 목표 음소를 산출하지 않는 경우로, /ㅅ/가 아예 빠져야 한다.", "왜곡": "왜곡은 목표 음소가 해당 언어 음소 목록에 없는 소리로 산출되는 경우이다.", "첨가": "첨가는 목표 단어에 없는 음소가 추가되는 경우이다."}'::jsonb, 1, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q3', 'communication-disorder', 'articulation', 'descriptive', '아동이 /시계/를 [ʃi게]로 발음했다. 이 오류가 ''대치''가 아닌 ''왜곡''으로 분류되는 이유를 설명하시오.', '2026학년도 전공B 4번 관련 출제 포인트', NULL, '[ʃ](권설 마찰음)는 한국어 음소 목록에 존재하지 않는 소리이므로 왜곡에 해당한다. 대치는 목표 음소가 해당 언어의 ''다른 음소''로 바뀌는 경우이고, 왜곡은 해당 언어 음소 목록에 없는 소리로 산출되는 경우이다.', '왜곡과 대치의 핵심 구분 기준은 산출된 소리가 해당 언어의 음소 목록에 존재하는지 여부이다. [ʃ]는 영어에는 있으나 한국어 음소 체계에는 없으므로 왜곡으로 분류한다. 이 구분은 2026 임용시험에서 직접 출제되었다.', NULL, 3, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q4', 'communication-disorder', 'articulation', 'fill_in', '아동이 /가방/을 [다방], /고래/를 [도래]로 발음하는 음운변동은 연구개음이 치경음으로 바뀌는 ______이다.', NULL, NULL, '전설음화(fronting)', '전설음화(fronting)는 연구개음(/ㄱ/, /ㅋ/)이 더 앞쪽 조음 위치인 치경음(/ㄷ/, /ㅌ/)으로 대치되는 음운변동이다. 조음 위치가 뒤(연구개)에서 앞(치경)으로 이동하므로 전설음화라고 한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q5', 'communication-disorder', 'articulation', 'ox', '조음치료에서 전통적 접근법(Van Riper)은 감각-지각 훈련 → 음 산출 → 음 안정화 → 전이·유지의 순서로 진행된다.', NULL, NULL, 'O', 'Van Riper의 전통적 조음치료 접근법은 감각-지각 훈련(귀 훈련), 음 산출(산출 훈련), 음 안정화(다양한 음성적 맥락에서 연습), 전이·유지(일상생활 일반화)의 4단계로 구성된다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q6', 'communication-disorder', 'aac', 'fill_in', 'AAC 참여모델에서 장벽은 크게 기회 장벽과 ______ 장벽으로 구분된다.', NULL, NULL, '접근(access)', 'AAC 참여모델(Participation Model)은 의사소통 참여를 저해하는 요인을 기회 장벽(opportunity barriers)과 접근 장벽(access barriers)으로 구분한다. 기회 장벽은 정책, 실제, 태도, 지식, 기술 장벽을 포함하며, 접근 장벽은 AAC 체계 자체에 대한 접근성 문제이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q7', 'communication-disorder', 'aac', 'descriptive', 'AAC 참여모델의 기회 장벽 5가지 하위 유형을 쓰고, ''태도 장벽''의 예를 1가지 서술하시오.', '2026학년도 전공B 4번 관련 출제 포인트', NULL, '기회 장벽의 5가지 하위 유형: 정책 장벽, 실제 장벽, 태도 장벽, 지식 장벽, 기술 장벽. 태도 장벽 예시: 교사나 또래가 AAC 사용자는 의사소통 능력이 부족하다고 여겨 대화 시도를 하지 않거나, AAC 기기를 사용하는 것이 부자연스럽다고 생각하여 상호작용을 회피하는 경우.', '태도 장벽은 주변 사람들의 부정적 인식이나 편견으로 인해 AAC 사용자의 의사소통 참여가 제한되는 것이다. 2026 임용시험에서 태도 장벽이 직접 출제되었으므로 각 장벽 유형의 정의와 구체적 예시를 숙지해야 한다.', NULL, 3, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q8', 'communication-disorder', 'aac', 'fill_in', 'AAC 상징의 도상성(iconicity) 수준은 투명(transparent), ______, 불투명(opaque)의 3단계로 구분된다.', NULL, NULL, '반투명(translucent)', '도상성은 상징이 지시 대상과 얼마나 닮았는지를 나타내는 정도이다. 투명(transparent)은 상징만 보고 의미를 알 수 있는 수준, 반투명(translucent)은 의미를 알고 나면 상징과의 관계를 이해할 수 있는 수준, 불투명(opaque)은 상징과 의미 사이에 시각적 유사성이 없는 수준이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q9', 'communication-disorder', 'aac', 'descriptive', '음성출력 의사소통 기기(VOCA/SGD)의 장점 중 ''의사소통 상대자 훈련이 불필요하다''는 것이 왜 중요한 장점인지 설명하시오.', NULL, NULL, '비도움 AAC(수어, 제스처 등)는 상대자도 해당 체계를 알아야 의사소통이 가능하여 상대자 훈련이 필수적이다. 반면 VOCA/SGD는 음성으로 메시지를 출력하므로 상대자가 별도의 훈련 없이도 메시지를 이해할 수 있다. 이는 낯선 사람과도 즉시 의사소통할 수 있어 사회적 참여 범위를 넓힌다.', 'VOCA/SGD는 합성 또는 녹음된 음성을 출력하여 누구나 메시지를 이해할 수 있게 한다. 이는 의사소통 상대자의 범위를 훈련받은 사람에 한정하지 않으므로, 통합 환경에서 특히 중요한 장점이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q10', 'communication-disorder', 'aac', 'multiple', 'AAC 상징 중 도상성이 가장 높은 것은?', NULL, ARRAY['블리스 상징(Blissymbols)', '실물 사진', 'PCS(Picture Communication Symbols)', '글자(text)']::text[], '실물 사진', '실물 사진은 지시 대상을 직접 촬영한 것으로 도상성이 가장 높다(투명). PCS는 그림 상징으로 비교적 높은 도상성을 가지지만 사진보다는 낮다. 블리스 상징과 글자는 추상적이므로 도상성이 낮다(불투명).', '{"블리스 상징(Blissymbols)": "블리스 상징은 의미 기반의 추상적 상징 체계로, 도상성이 낮아 불투명에 가깝다.", "PCS(Picture Communication Symbols)": "PCS는 그림 상징으로 비교적 높은 도상성을 가지나, 실물 사진보다는 추상화되어 있다.", "글자(text)": "글자는 소리와 의미의 관계가 자의적이므로 도상성이 가장 낮다."}'::jsonb, 1, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q11', 'communication-disorder', 'spontaneous-speech', 'fill_in', '평균발화길이(MLU)의 계산 공식은 총 ______ 수 ÷ 총 발화 수이다.', NULL, NULL, '형태소', 'MLU(Mean Length of Utterance, 평균발화길이)는 총 형태소 수를 총 발화 수로 나눈 값이다. 한국어에서는 어절 기준 MLUw와 형태소 기준 MLUm을 모두 사용하나, 전통적으로 형태소 단위(MLUm)가 기본이다.', NULL, 1, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q12', 'communication-disorder', 'spontaneous-speech', 'descriptive', '자발화 분석에서 NDW(Number of Different Words)와 TNW(Total Number of Words)의 차이를 설명하고, NDW/TNW 비율이 낮을 때 의미하는 바를 서술하시오.', NULL, NULL, 'NDW는 아동이 산출한 서로 다른 낱말의 수(중복 제외)이고, TNW는 산출한 전체 낱말 수(중복 포함)이다. NDW/TNW 비율(TTR: Type-Token Ratio)이 낮으면 아동이 제한된 어휘를 반복적으로 사용하고 있음을 의미하며, 어휘 다양성이 낮다는 것을 나타낸다.', 'TTR(Type-Token Ratio)은 어휘 다양성의 지표로, 비율이 낮을수록 동일한 단어를 반복 사용하는 경향이 크다. 언어발달 지연 아동은 일반 아동에 비해 TTR이 낮은 경향이 있다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q13', 'communication-disorder', 'spontaneous-speech', 'ox', '자발화 분석 시 MLU 산출을 위해서는 최소 50개 이상의 완전한 발화를 수집하는 것이 권장된다.', NULL, NULL, 'O', '자발화 분석에서 MLU의 대표성을 확보하기 위해 최소 50~100개의 완전한 발화 표본을 수집하는 것이 권장된다. 표본이 너무 적으면 아동의 언어 능력을 정확하게 반영하지 못할 수 있다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q14', 'communication-disorder', 'emt', 'fill_in', '환경중심 언어중재(EMT)의 4가지 기법은 모델링, 요구-모델, ______, 우발교수이다.', NULL, NULL, '시간지연(time delay)', 'EMT의 4가지 기법은 모델링(modeling), 요구-모델(mand-model), 시간지연(time delay), 우발교수(incidental teaching)이다. 시간지연은 아동이 원하는 것이 있을 때 성인이 일정 시간 기다려 아동의 자발적 의사소통을 유도하는 기법이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q15', 'communication-disorder', 'emt', 'descriptive', '환경중심 언어중재에서 ''요구-모델(mand-model)'' 기법의 절차를 단계별로 설명하시오.', NULL, NULL, '1단계: 아동의 관심이나 요구를 관찰하여 의사소통 기회를 포착한다. 2단계: 아동에게 언어적 요구(mand)를 한다(예: ''뭐 갖고 싶어?'', ''이름이 뭐야?''). 3단계: 아동이 적절히 반응하면 원하는 것을 제공하고, 반응이 없거나 부적절하면 목표 언어를 모델링한다. 4단계: 아동이 모델을 모방하면 강화(원하는 것 제공)하고, 모방하지 못해도 원하는 것을 제공하되 목표 언어를 한 번 더 들려준다.', '요구-모델 기법은 아동의 자연스러운 동기를 활용하되, 먼저 언어적 요구(질문)를 통해 자발적 산출을 유도하고, 실패 시 모델링으로 전환하는 촉진 계층 구조를 가진다.', NULL, 3, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q16', 'communication-disorder', 'emt', 'multiple', '환경중심 언어중재 기법 중, 성인이 아동이 원하는 물건을 보여주고 아무 말 없이 일정 시간 기다려 아동의 자발적 발화를 유도하는 기법은?', NULL, ARRAY['모델링', '요구-모델', '시간지연', '우발교수']::text[], '시간지연', '시간지연(time delay)은 아동이 원하는 상황에서 성인이 기대하는 표정으로 일정 시간(보통 5~15초) 기다려 아동의 자발적 의사소통 시도를 유도하는 기법이다. 언어적 촉진 없이 비언어적 단서(시선, 기대 표정)만 제공하는 것이 특징이다.', '{"모델링": "모델링은 성인이 먼저 목표 언어를 들려주는 기법으로, 기다리지 않고 즉시 모델을 제공한다.", "요구-모델": "요구-모델은 성인이 언어적 질문(''뭐야?'')으로 반응을 요구하는 기법이다.", "우발교수": "우발교수는 아동이 먼저 시도한 후 성인이 더 정교한 반응을 요구하는 기법이다."}'::jsonb, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q17', 'communication-disorder', 'emt', 'fill_in', '환경중심 언어중재에서 ______ 기법은 아동이 먼저 원하는 것을 요청(시작)한 후, 성인이 더 정교화된 언어 반응을 요구하는 방식이다.', NULL, NULL, '우발교수(incidental teaching)', '우발교수는 아동이 자발적으로 의사소통을 시작했을 때 성인이 더 구체적이거나 정교한 언어 표현을 요구하는 기법이다. 아동의 자발적 시작이 전제 조건이라는 점에서 다른 EMT 기법과 구별된다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q18', 'communication-disorder', 'fluency', 'fill_in', '말더듬의 핵심행동(core behaviors) 3가지는 반복(part-word repetition), 연장(prolongation), ______이다.', NULL, NULL, '막힘(block)', '말더듬의 핵심행동은 반복(음절이나 음소 단위의 반복), 연장(소리를 길게 늘이는 것), 막힘(공기 흐름이나 발성이 일시적으로 차단되는 것)의 3가지이다. 이는 부수행동(탈출행동, 회피행동)과 구별되는 말더듬의 본질적 특성이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q19', 'communication-disorder', 'fluency', 'descriptive', '유창성완성법(fluency shaping)과 말더듬수정법(stuttering modification)의 치료 목표와 접근 방식의 차이를 비교 설명하시오.', NULL, NULL, '유창성완성법은 유창한 말을 증진하는 것이 목표로, 말더듬을 직접 다루기보다 부드러운 발성 시작, 느린 말 속도, 연속적 발성 등 유창성을 촉진하는 새로운 말 패턴을 훈련한다. 말더듬수정법은 말더듬 자체를 수정하는 것이 목표로, 말더듬에 대한 두려움과 회피를 줄이고, 더 쉬운 말더듬(easier stuttering)으로 변환하는 것을 추구한다. 말더듬수정법의 4단계는 확인(identification), 둔감화(desensitization), 수정(modification), 안정화(stabilization)이다.', '유창성완성법은 말더듬을 피하고 유창성을 만드는 접근이고, 말더듬수정법은 말더듬을 수용하되 더 편하게 더듬도록 하는 접근이다. 현대 치료에서는 두 접근을 통합적으로 사용하는 경향이 있다.', NULL, 3, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('cd-q20', 'communication-disorder', 'fluency', 'ox', '말더듬에서 머리를 흔들거나 눈을 깜빡이는 행동은 핵심행동(core behaviors)에 해당한다.', NULL, NULL, 'X', '머리 흔들기, 눈 깜빡이기 등은 부수행동(secondary behaviors) 중 탈출행동에 해당한다. 핵심행동은 반복, 연장, 막힘의 3가지이며, 부수행동은 말더듬 순간에서 벗어나기 위한 탈출행동과 말더듬 상황을 미리 피하려는 회피행동으로 나뉜다.', NULL, 1, 'KICE 기출 기반', '{"disability": "의사소통장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q1', 'hearing-impairment', 'audiogram', 'fill_in', '순음청력검사에서 기도청력역치와 골도청력역치의 차이를 ( )(이)라 하며, 이 값이 10dB 이상일 경우 전음성 난청을 의심할 수 있다.', NULL, NULL, '기도-골도 차이(air-bone gap)', '기도검사는 외이→중이→내이를 거치는 전체 청각 경로를, 골도검사는 중이를 우회하여 내이 기능만을 평가한다. 따라서 기도-골도 차이(air-bone gap)가 10dB 이상이면 중이에 문제가 있는 전음성 난청을 시사한다.', NULL, 1, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q2', 'hearing-impairment', 'audiogram', 'fill_in', '청력손실 정도 분류에서 순음청력역치 평균이 71~90dB HL인 경우 ( ) 난청으로 분류한다.', NULL, NULL, '고도(severe)', '청력손실 정도 분류: 경도 26~40dB, 중등도 41~55dB, 중고도 56~70dB, 고도 71~90dB, 최고도 91dB 이상이다. 고도 난청 학생은 보청기를 착용해도 말소리 지각에 상당한 어려움이 있어 시각적 의사소통 수단의 보완이 필요하다.', NULL, 1, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q3', 'hearing-impairment', 'audiogram', 'multiple', '다음 중 감각신경성 난청의 청력도 특성으로 옳은 것은?', NULL, ARRAY['기도역치는 정상이나 골도역치만 저하되어 있다.', '기도역치와 골도역치가 모두 저하되어 있으며, 기도-골도 차이가 거의 없다.', '기도역치만 저하되어 있고 골도역치는 정상 범위이다.', '저주파 영역에서만 역치가 저하되고 고주파는 정상이다.']::text[], '기도역치와 골도역치가 모두 저하되어 있으며, 기도-골도 차이가 거의 없다.', '감각신경성 난청은 내이(와우) 또는 청신경의 손상으로 발생하므로, 기도와 골도 모두 역치가 저하되며 기도-골도 차이가 10dB 미만으로 거의 나타나지 않는다. 선택지 ③은 전음성 난청의 특성이고, 선택지 ①은 검사상 나타날 수 없는 패턴이다.', '{"기도역치는 정상이나 골도역치만 저하되어 있다.": "골도역치가 기도역치보다 나쁠 수 없다. 골도는 중이를 우회하므로 기도역치보다 항상 같거나 더 좋다.", "기도역치만 저하되어 있고 골도역치는 정상 범위이다.": "이는 전음성 난청의 전형적 패턴이다. 감각신경성 난청에서는 골도역치도 함께 저하된다.", "저주파 영역에서만 역치가 저하되고 고주파는 정상이다.": "감각신경성 난청은 오히려 고주파 영역에서 역치 저하가 심한 경우가 많으며, 전 주파수에 걸쳐 나타날 수 있다."}'::jsonb, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q4', 'hearing-impairment', 'audiogram', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '초등학교 3학년 민수의 순음청력검사 결과, 우측 귀의 기도청력역치는 500Hz 55dB, 1000Hz 60dB, 2000Hz 65dB이고, 골도청력역치는 500Hz 50dB, 1000Hz 55dB, 2000Hz 60dB이다. 좌측 귀의 기도청력역치는 500Hz 30dB, 1000Hz 35dB, 2000Hz 40dB이고, 골도청력역치는 500Hz 15dB, 1000Hz 15dB, 2000Hz 20dB이다.', NULL, '(1) 우측 귀: 3분법 평균 청력역치 = (55+60+65)/3 = 60dB → 중고도 난청. 기도-골도 차이가 5dB로 감각신경성 난청이다.
(2) 좌측 귀: 3분법 평균 청력역치 = (30+35+40)/3 = 35dB → 경도 난청. 기도-골도 차이가 15~20dB로 전음성 요소가 포함된 혼합성 난청이다.
(3) 양 귀의 난청 유형이 다르므로, 좌측 귀의 전음성 요소에 대해 이비인후과적 치료 가능성을 탐색하고, 우측 귀에는 보청기 적합을 우선 고려해야 한다.', '3분법(500Hz, 1000Hz, 2000Hz 평균)은 어음 주파수대 청력을 대표하는 지표이다. 기도-골도 차이가 10dB 이상이면 전음성 요소가 있음을 의미하며, 좌측 귀는 혼합성 난청으로 판단한다. 양이 비대칭 난청인 경우 각 귀에 대한 개별적 중재 계획이 필요하다.', NULL, 3, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q5', 'hearing-impairment', 'audiogram', 'ox', '순음청력검사에서 주파수(Hz)는 청력도의 세로축에, 청력역치(dB HL)는 가로축에 표시한다.', NULL, NULL, 'X', '청력도(audiogram)에서 가로축은 주파수(Hz)를, 세로축은 청력역치(dB HL)를 나타낸다. 세로축은 위쪽이 0dB(좋은 청력)이고 아래로 갈수록 숫자가 커져 청력손실이 심함을 의미한다. 가로축은 왼쪽에서 오른쪽으로 갈수록 저주파에서 고주파로 이동한다.', NULL, 1, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q6', 'hearing-impairment', 'cochlear-implant', 'fill_in', '인공와우 수술 후 외부장치의 전극별 자극량을 청각적 반응에 맞추어 조절하는 과정을 ( )(이)라 한다.', NULL, NULL, '매핑(mapping)', '매핑(mapping)은 인공와우 착용자가 편안하고 적절한 소리를 들을 수 있도록 각 전극의 최소 자극량(T-level)과 최대 안락 수준(C-level)을 설정하는 과정이다. 수술 후 초기에는 자주, 이후 점차 간격을 두고 실시하며, 특히 영유아의 경우 행동반응 관찰이 중요하다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q7', 'hearing-impairment', 'cochlear-implant', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '만 2세 영아 지은이는 양측 고도 감각신경성 난청(양이 평균 95dB HL)으로 진단받았다. 6개월간 보청기를 착용하였으나 어음변별력이 10% 미만이다. 부모는 인공와우 수술을 고려하고 있으며, 특수교사에게 인공와우에 대한 정보를 요청하였다.', NULL, '(1) 인공와우 적응증: 양측 고도 이상 난청, 보청기로 충분한 효과를 얻지 못하는 경우, 청각재활 의지가 있는 경우에 해당하며 지은이는 이 조건을 충족한다.
(2) 조기 수술의 이점: 청각 발달의 결정적 시기(3세 이전)에 수술하면 청각 피질의 가소성을 활용하여 듣기 및 구어 발달에 유리하다.
(3) 수술 후 재활: 매핑을 통한 기기 조절, 청각구어법(AVT) 등 체계적인 청능훈련이 필수적이며, 가정에서의 풍부한 언어 입력 환경 조성이 중요하다.
(4) 부모에게 안내할 사항: 인공와우는 정상 청력을 회복시키는 것이 아니며, 장기적인 재활과 기기 관리가 필요하다는 현실적 기대를 갖도록 안내한다.', '인공와우는 와우 내 전극을 삽입하여 청신경을 직접 전기 자극하는 장치이다. 보청기와 달리 소리를 증폭하는 것이 아니라 전기 신호로 변환하여 전달한다. 영유아기 조기 이식은 청각-언어 발달의 결정적 시기를 활용할 수 있어 효과적이며, 수술 후 체계적인 청능재활이 성과를 좌우한다.', NULL, 3, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q8', 'hearing-impairment', 'cochlear-implant', 'ox', '인공와우는 소리를 증폭하여 잔존 유모세포를 자극하는 원리로 작동한다.', NULL, NULL, 'X', '인공와우는 소리를 증폭하는 것이 아니라, 음향 신호를 전기 신호로 변환하여 와우 내 삽입된 전극을 통해 청신경을 직접 자극하는 장치이다. 유모세포를 우회(bypass)하여 작동하므로 유모세포의 손상 여부와 관계없이 청신경이 기능하면 사용할 수 있다. 소리를 증폭하여 유모세포를 자극하는 것은 보청기의 원리이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q9', 'hearing-impairment', 'hearing-aid', 'fill_in', '보청기 이득(gain) 계산에서, 청력역치의 1/2에 해당하는 이득을 처방하는 방식을 ( ) 규칙이라 한다.', NULL, NULL, '1/2 이득 규칙(half-gain rule)', '1/2 이득 규칙은 Lybarger가 제안한 보청기 이득 처방 공식으로, 각 주파수에서 청력역치의 절반에 해당하는 이득을 제공한다. 예를 들어 1000Hz에서 역치가 60dB이면 30dB의 이득을 처방한다. 간편하여 널리 사용되나, 개인의 쾌적 수준과 어음 명료도를 고려한 미세 조정이 필요하다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q10', 'hearing-impairment', 'hearing-aid', 'fill_in', '보청기 유형 중 귀걸이형 보청기의 본체에서 리시버(수화기)를 분리하여 외이도 내에 직접 배치하는 방식을 ( ) 보청기라 한다.', NULL, NULL, 'RIC(Receiver-In-Canal)', 'RIC(Receiver-In-Canal) 보청기는 귀걸이형(BTE)과 유사하지만, 리시버를 본체에서 분리하여 외이도 안에 배치한다. 이로써 본체가 소형화되고, 음향 피드백(하울링)이 감소하며, 자연스러운 음질을 제공할 수 있다. 현재 가장 많이 처방되는 보청기 유형 중 하나이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q11', 'hearing-impairment', 'hearing-aid', 'multiple', '보청기 관리에 대한 설명으로 옳지 않은 것은?', NULL, ARRAY['이어몰드는 미지근한 비눗물로 세척한 후 완전히 건조시킨다.', '보청기 본체는 물로 세척하지 않고 부드러운 천으로 닦는다.', '사용하지 않을 때는 배터리를 넣은 채 배터리 문을 닫아 보관한다.', '습기 제거를 위해 건조기(드라이 키트)에 보관하는 것이 좋다.']::text[], '사용하지 않을 때는 배터리를 넣은 채 배터리 문을 닫아 보관한다.', '보청기를 사용하지 않을 때는 배터리 문을 열어두거나 배터리를 분리하여 보관해야 한다. 배터리 문을 닫아두면 전력이 소모되고 습기가 차서 내부 부품이 손상될 수 있다. 이어몰드는 보청기 본체에서 분리한 후 비눗물로 세척 가능하나, 보청기 본체 자체는 물에 접촉시키면 안 된다.', '{"이어몰드는 미지근한 비눗물로 세척한 후 완전히 건조시킨다.": "이어몰드는 보청기 본체에서 분리하여 비눗물로 세척할 수 있다. 완전 건조 후 다시 연결한다.", "보청기 본체는 물로 세척하지 않고 부드러운 천으로 닦는다.": "보청기 본체에는 전자 부품이 있어 물에 접촉하면 고장의 원인이 된다. 부드러운 천이나 전용 브러시로 관리한다.", "습기 제거를 위해 건조기(드라이 키트)에 보관하는 것이 좋다.": "보청기는 습기에 취약하므로 매일 밤 건조기에 넣어 습기를 제거하는 것이 권장된다."}'::jsonb, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q12', 'hearing-impairment', 'hearing-aid', 'descriptive', '보청기의 주요 유형(BTE, RIC, ITE, ITC, CIC) 중 3가지를 선택하여 각각의 특징, 장점, 적합 대상을 비교·설명하시오.', NULL, NULL, '(1) BTE(귀걸이형): 본체가 귓바퀴 뒤에 위치하며 튜브를 통해 이어몰드와 연결된다. 출력이 크고 조작이 용이하여 경도~최고도 난청까지 폭넓게 적합하다. 소아는 귀 성장에 따라 이어몰드만 교체하면 되므로 경제적이다.
(2) RIC(외이도 내 리시버형): 리시버가 외이도 안에 위치하여 BTE보다 소형이고 음질이 자연스럽다. 경도~고도 난청에 적합하며 피드백이 적다.
(3) CIC(고막형): 외이도 깊숙이 삽입되어 외부에서 거의 보이지 않는다. 미용적 장점이 크나 출력이 제한적이어서 경도~중등도 난청에 적합하고, 소형이라 조작과 관리가 어려울 수 있다.', '보청기 유형 선택 시 난청 정도, 외이도 크기, 조작 능력, 미용적 선호도, 연령 등을 종합적으로 고려해야 한다. 소아에게는 안전성과 성장 대응이 용이한 BTE가 주로 권장되며, 성인은 생활양식과 난청 정도에 따라 RIC, ITE, CIC 등을 선택한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q13', 'hearing-impairment', 'sign-language', 'fill_in', '한국수어의 음운에 해당하는 5가지 매개변수는 수형, 수위, 수동, ( ), 비수지 신호이다.', NULL, NULL, '수향(手向, palm orientation)', '한국수어의 수어소(cheremes)는 수형(handshape), 수위(location), 수동(movement), 수향(palm orientation), 비수지 신호(non-manual signals)의 5가지 매개변수로 구성된다. 수향은 손바닥이 향하는 방향을 의미하며, 동일한 수형·수위·수동이라도 수향이 달라지면 다른 의미를 나타낼 수 있다.', NULL, 1, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q14', 'hearing-impairment', 'sign-language', 'fill_in', '청각장애인이 고유명사, 외래어 등 수어 어휘가 없는 단어를 표현할 때 자모 하나하나를 손 모양으로 나타내는 것을 ( )(이)라 한다.', NULL, NULL, '지문자(fingerspelling)', '지문자는 한글 자모(ㄱ, ㄴ, ㄷ… / ㅏ, ㅓ, ㅗ…)를 각각 고유한 손 모양으로 표현하는 체계이다. 한국 지문자는 한 손으로 표현하며, 수어 어휘가 존재하지 않는 고유명사, 외래어, 전문 용어 등을 표기할 때 주로 사용한다.', NULL, 3, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q15', 'hearing-impairment', 'sign-language', 'multiple', '한국수어에 대한 설명으로 옳은 것은?', NULL, ARRAY['한국수어는 한국어의 어순을 그대로 따르는 수단적 체계이다.', '한국수어법(2016)에 의해 한국수어는 한국어와 동등한 자격을 가진 농인의 공용어로 인정되었다.', '한국수어는 음운에 해당하는 변별적 단위가 존재하지 않는 몸짓 언어이다.', '한국수어의 문법은 영어 수어(ASL)와 동일한 구조를 가진다.']::text[], '한국수어법(2016)에 의해 한국수어는 한국어와 동등한 자격을 가진 농인의 공용어로 인정되었다.', '2016년 제정된 한국수어법은 한국수어를 대한민국 농인의 공용어로 인정하고, 한국어와 동등한 자격을 부여하였다. 한국수어는 한국어와 독립된 문법 체계(SOV 경향이 있으나 한국어와 다른 어순 규칙)를 가진 자연언어이며, 수형·수위·수동·수향·비수지 신호라는 변별적 단위(수어소)를 갖추고 있다.', '{"한국수어는 한국어의 어순을 그대로 따르는 수단적 체계이다.": "한국어 어순을 따르는 것은 한국어 대응 수어(수지한국어)이다. 한국수어는 독자적 문법 구조를 가진 자연언어이다.", "한국수어는 음운에 해당하는 변별적 단위가 존재하지 않는 몸짓 언어이다.": "한국수어는 수형, 수위, 수동, 수향, 비수지 신호의 5가지 매개변수로 구성된 이중분절 체계를 갖춘 자연언어이다.", "한국수어의 문법은 영어 수어(ASL)와 동일한 구조를 가진다.": "각 나라의 수어는 독립적으로 발달한 자연언어로, 한국수어와 ASL은 서로 다른 문법 구조를 가진다."}'::jsonb, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q16', 'hearing-impairment', 'sign-language', 'descriptive', '청각장애 학생의 의사소통 교육 접근법인 구화법, 수어법, 토탈커뮤니케이션(TC)을 각각 설명하고, 장단점을 비교하시오.', NULL, NULL, '(1) 구화법(oral method): 독화(입 읽기), 잔존청력 활용, 발화 훈련을 통해 음성언어로 의사소통하는 방법이다. 장점은 건청인과의 직접 소통이 가능하다는 것이나, 고도 이상 난청 학생에게는 습득이 어렵고 독화만으로는 정보 수용에 한계가 있다.
(2) 수어법(manual method): 수어와 지문자를 주된 의사소통 수단으로 사용한다. 시각 언어이므로 청력 수준과 관계없이 습득 가능하고, 농문화 정체성 형성에 기여한다. 그러나 건청인 사회와의 소통에 통역이 필요하고, 한국어 문해력과 직접 연결되지 않을 수 있다.
(3) 토탈커뮤니케이션(TC): 구어, 수어, 지문자, 독화, 필담, 몸짓 등 활용 가능한 모든 의사소통 수단을 사용하는 접근법이다. 학생의 개별 요구에 유연하게 대응할 수 있으나, 두 언어를 동시에 제시하면 각각의 완전한 모형 입력이 어려울 수 있다.', '의사소통 접근법 선택은 학생의 청력 수준, 보장구 착용 효과, 인지 능력, 가정 환경, 농문화 정체성 등을 종합적으로 고려해야 한다. 최근에는 이중언어-이중문화(Bi-Bi) 접근이 주목받고 있으며, 수어를 제1언어로, 한국어(문어)를 제2언어로 교육하는 방법이다.', NULL, 3, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q17', 'hearing-impairment', 'sign-language', 'descriptive', '이중언어-이중문화(Bi-Bi) 접근법의 개념과 원리를 설명하고, 청각장애 학생 교육에서의 적용 방안을 2가지 서술하시오.', NULL, NULL, '(1) 개념: 이중언어-이중문화(Bilingual-Bicultural, Bi-Bi) 접근법은 수어를 청각장애 학생의 제1언어(L1)로, 해당 국가의 음성/문자 언어(한국어)를 제2언어(L2)로 교육하는 방법이다. 동시에 농문화와 건청 문화 모두에 대한 이해와 정체성을 형성하도록 한다.
(2) 적용 방안 ①: 수어를 교수 언어로 사용하여 교과 내용을 전달하고, 한국어 문해력은 읽기·쓰기를 통해 별도로 지도한다. L1의 언어 능력이 L2 학습의 기반이 된다는 상호의존가설(Cummins)에 근거한다.
(3) 적용 방안 ②: 농인 교사 또는 농인 보조인력을 배치하여 수어 모형(language model)을 제공하고, 건청 교사는 한국어 문해력 지도를 담당하는 협력 교수 체계를 구축한다.', 'Bi-Bi 접근은 농인을 언어적·문화적 소수자로 보는 관점에 기반하며, 수어를 결함 보상 수단이 아닌 완전한 자연언어로 인정한다. 한국수어법(2016) 제정 이후 이중언어 교육에 대한 법적 근거가 마련되었다.', NULL, 3, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q18', 'hearing-impairment', 'classroom', 'fill_in', '교실에서 청각장애 학생의 말소리 지각을 돕기 위해 교사의 음성을 무선으로 전달하여 ( )를 개선하는 보조공학 기기를 FM 보청시스템이라 한다.', NULL, NULL, '신호대잡음비(SNR, Signal-to-Noise Ratio)', 'FM 보청시스템은 교사가 송신기(마이크)를 착용하고 학생이 수신기를 보청기/인공와우에 연결하여 사용한다. 교사의 음성(신호)을 직접 전달함으로써 교실 소음(잡음)에 비해 신호를 크게 하여 신호대잡음비(SNR)를 약 15~20dB 개선한다. 이를 통해 거리와 소음으로 인한 말소리 왜곡 문제를 극복할 수 있다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q19', 'hearing-impairment', 'classroom', 'ox', '청각장애 학생의 좌석은 교실 맨 뒷자리에 배치하여 전체 학급 학생의 입 모양을 볼 수 있도록 하는 것이 가장 효과적이다.', NULL, NULL, 'X', '청각장애 학생은 교사의 얼굴(입 모양, 표정)을 가까이에서 명확하게 볼 수 있도록 교실 앞쪽에 배치하는 것이 원칙이다. 말소리 강도는 거리의 제곱에 반비례하여 감소하므로(역자승 법칙), 뒷자리에서는 신호대잡음비가 크게 저하된다. 또한 교사와 급우의 발언을 모두 볼 수 있는 반원형(말굽형) 좌석 배치가 효과적이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('hi-q20', 'hearing-impairment', 'classroom', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '통합학급 담임교사 김 교사는 중고도 난청(양이 평균 62dB HL)으로 보청기를 착용한 초등 4학년 수진이를 담당하고 있다. 교실은 30명 학생이 있으며, 복도 쪽 창문을 열어두면 소음이 유입된다. 김 교사는 수진이의 수업 참여도가 낮다는 것을 발견하였다.', NULL, '(1) 물리적 환경 조성: 복도 쪽 창문에 방음 조치를 하거나 수업 중 창문을 닫아 외부 소음을 차단한다. 교실 바닥에 카펫을 깔거나 의자 다리에 테니스공을 부착하여 실내 소음을 감소시킨다.
(2) 보조공학 활용: FM 보청시스템을 도입하여 교사 음성을 직접 전달함으로써 신호대잡음비를 개선한다. 사운드필드 시스템도 학급 전체에 도움이 된다.
(3) 좌석 배치: 수진이를 교사 가까이 앞쪽에 배치하되, 교사의 얼굴을 정면으로 볼 수 있는 위치에 둔다. 토론 시에는 반원형 배치로 전환한다.
(4) 교수 전략: 핵심 어휘를 칠판에 미리 판서하고, 시각 자료(PPT, 그림, 자막)를 적극 활용한다. 또래 노트테이커를 지정하여 수업 내용을 보완한다.', '청각장애 학생의 통합교육에서는 음향 환경 개선, 보조공학 활용, 좌석 배치, 교수 방법 수정 등 다차원적 지원이 필요하다. 소음 관리는 가장 기본적이면서도 효과적인 지원이며, 교실 소음을 35dB(A) 이하로 유지하고 잔향 시간을 0.6초 이내로 관리하는 것이 권장된다.', NULL, 3, 'KICE 기출 기반', '{"disability": "청각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q31', 'laws', 'theory', 'fill_in', '「장애인 등에 대한 특수교육법」 제15조에 따르면, 특수교육대상자의 선정은 ( )의 진단·평가 결과를 기초로 하여 시·도 교육감 또는 교육장이 결정한다. 빈칸에 들어갈 기관을 쓰시오.', NULL, NULL, '특수교육지원센터', '특수교육법 제15조 제1항에 따르면, 교육장 또는 교육감은 특수교육지원센터의 진단·평가 결과를 기초로 특수교육대상자를 선정한다. 특수교육지원센터는 진단·평가를 의뢰받은 후 30일 이내에 진단·평가를 시행하여야 한다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q32', 'laws', 'theory', 'multiple', '「장애인 등에 대한 특수교육법」 제17조(특수교육대상자의 배치)에 관한 설명으로 옳지 않은 것은?', NULL, ARRAY['교육장 또는 교육감은 특수교육대상자를 일반학교의 일반학급, 일반학교의 특수학급, 특수학교에 배치할 수 있다.', '특수교육대상자의 배치는 특수교육대상자의 장애 정도에 따라 특수학교를 우선적으로 고려하여야 한다.', '교육장 또는 교육감은 특수교육대상자를 배치할 때 해당 학교의 장과 특수교육대상자에게 각각 통보하여야 한다.', '특수교육대상자의 배치 시 특수교육운영위원회의 심사를 거쳐야 한다.']::text[], '2', '특수교육법 제17조에 따르면, 특수교육대상자의 배치는 일반학교의 일반학급에 우선 배치하는 통합교육을 원칙으로 한다. 장애 정도에 따라 특수학교를 우선 고려하는 것은 법의 취지에 반한다. 일반학급 → 특수학급 → 특수학교의 최소제한환경(LRE) 원칙을 따른다.', '{"1": "제17조 제1항에 명시된 배치 유형으로 정확하다.", "3": "제17조 제2항에 따라 해당 학교의 장과 특수교육대상자에게 통보한다.", "4": "제17조에 따라 배치 시 특수교육운영위원회의 심사를 거쳐야 한다."}'::jsonb, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q33', 'laws', 'practices', 'descriptive', '「장애인 등에 대한 특수교육법」 제22조에 규정된 개별화교육계획(IEP)에 대해 다음 세 가지를 서술하시오: (1) 작성 의무 시기, (2) 개별화교육지원팀의 구성원 3인 이상, (3) IEP에 반드시 포함되어야 할 내용 3가지 이상.', NULL, NULL, '(1) 매 학년의 시작일로부터 2주 이내에 개별화교육지원팀을 구성하고, 30일 이내에 개별화교육계획을 작성하여야 한다. (2) 구성원: 보호자, 특수교육교원, 일반교육교원, 진로 및 직업교육 담당 교원, 특수교육 관련서비스 담당 인력 등. (3) 포함 내용: 특수교육대상자의 인적사항, 현재 학습 수행수준, 교육목표, 교육내용, 교육방법, 평가계획, 특수교육 관련서비스의 내용과 방법 등.', '특수교육법 제22조에 따라 각급학교의 장은 매 학년 시작일부터 2주 이내에 개별화교육지원팀을 구성하고, 1개월(30일) 이내에 IEP를 작성해야 한다. 개별화교육지원팀은 보호자, 특수교육교원, 일반교육교원, 진로 및 직업교육 담당 교원, 관련서비스 담당 인력 등으로 구성된다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q34', 'laws', 'practices', 'fill_in', '「장애인 등에 대한 특수교육법」 제28조에 따른 특수교육 관련서비스에는 상담지원, 가족지원, ( ① )지원, 보조인력지원, 보조공학기기지원, 통학지원, ( ② )지원이 포함된다. ①과 ②를 순서대로 쓰시오.', NULL, NULL, '① 치료, ② 의료적', '특수교육법 제28조에 명시된 특수교육 관련서비스 7종: 상담지원, 가족지원, 치료지원, 보조인력지원, 보조공학기기지원, 통학지원, 의료적 지원. 2026 개정에서 의료적 지원이 강조되고 있으며, 건강장애 학생 등에게 제공된다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q35', 'laws', 'practices', 'ox', '「장애인 등에 대한 특수교육법 시행령」 제29조에 따르면, 병원학교에서의 수업은 교육과정의 운영상 필요한 경우 한 교시의 수업시간을 40분으로 운영할 수 있다.', NULL, NULL, 'X', '시행령 제29조에 따르면 병원학교 및 원격수업에서의 한 교시 수업시간은 30분을 원칙으로 한다(40분이 아님). 건강장애 학생의 체력적 한계를 고려하여 일반학교(초 40분, 중 45분, 고 50분)보다 짧게 운영한다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q36', 'laws', 'strategies', 'descriptive', '특수교육지원센터의 주요 역할 3가지를 법적 근거와 함께 서술하시오.', NULL, NULL, '특수교육지원센터의 주요 역할: (1) 진단·평가: 특수교육법 제16조에 따라 특수교육대상자에 대한 진단·평가를 실시한다. (2) 순회교육: 특수교육법 제25조에 따라 일반학교에서 통합교육을 받고 있는 특수교육대상자를 지원하기 위해 순회교육을 실시한다. (3) 특수교육 관련서비스 제공: 제28조에 따라 상담지원, 가족지원, 치료지원 등 관련서비스를 제공한다.', '특수교육지원센터는 특수교육법 제11조에 근거하여 설치되며, 진단·평가(제16조), 순회교육(제25조), 관련서비스 제공(제28조) 등의 역할을 수행한다. 또한 특수교육대상자 및 보호자에 대한 정보 제공, 특수교육교원 연수 지원 등의 기능도 한다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('laws-q37', 'laws', 'strategies', 'ox', '「장애인복지법」에서는 장애를 15종으로 분류하고, 「장애인 등에 대한 특수교육법」에서는 장애를 10종으로 분류한다.', NULL, NULL, 'O', '장애인복지법은 지체, 뇌병변, 시각, 청각, 언어, 지적, 자폐성, 정신, 신장, 심장, 호흡기, 간, 안면, 장루·요루, 뇌전증 등 15종으로 분류한다. 특수교육법은 시각장애, 청각장애, 지적장애, 지체장애, 정서·행동장애, 자폐성장애, 의사소통장애, 학습장애, 건강장애, 발달지체 등 10종으로 분류한다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q31', 'transition', 'theory', 'fill_in', '전환교육의 4가지 핵심 구성요소(영역)는 교육, ( ① ), 일상생활, ( ② )이다. ①과 ②를 순서대로 쓰시오.', NULL, NULL, '① 고용, ② 지역사회참여', '전환교육의 4대 영역은 교육(education), 고용(employment), 일상생활(daily living), 지역사회참여(community participation)이다. 이는 Halpern(1985)의 모델에 기반하며, 학교에서 성인생활로의 성공적 전환을 위해 이 네 영역에서의 종합적인 지원이 필요하다.', NULL, 1, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q32', 'transition', 'theory', 'descriptive', 'Wehmeyer의 자기결정(self-determination) 모델에서 제시한 자기결정의 4가지 본질적 특성을 모두 쓰고, 각각을 한 문장으로 설명하시오.', NULL, NULL, '(1) 자율성(autonomy): 자신의 선호와 흥미에 따라 독립적으로 행동하는 것. (2) 자기조절(self-regulation): 자신의 행동을 점검하고 평가하여 조절하는 것. (3) 심리적 역량강화(psychological empowerment): 자신이 통제력을 가지고 있다고 믿는 것. (4) 자기실현(self-realization): 자신의 강점과 약점을 정확히 파악하고 활용하는 것.', 'Wehmeyer(1999)는 자기결정을 ''자신의 삶의 주된 주체로 행동하고, 외부의 부당한 영향이나 간섭 없이 자신의 삶의 질을 유지·향상시키는 선택과 결정을 하는 것''으로 정의했다. 4가지 본질적 특성(essential characteristics)은 자율성, 자기조절, 심리적 역량강화, 자기실현이다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q33', 'transition', 'theory', 'multiple', '자기옹호(self-advocacy)의 구성요소에 해당하지 않는 것은?', NULL, ARRAY['자기지식(knowledge of self)', '권리 인식(knowledge of rights)', '자기강화(self-reinforcement)', '의사소통(communication)']::text[], '3', '자기옹호의 구성요소는 자기지식(knowledge of self), 권리 인식(knowledge of rights), 의사소통(communication), 리더십(leadership)이다. 자기강화(self-reinforcement)는 자기관리(self-management) 전략의 구성요소에 해당하며, 자기옹호의 구성요소가 아니다.', '{"1": "자기옹호의 핵심 구성요소로, 자신의 강점·약점·필요를 이해하는 것이다.", "2": "자기옹호의 핵심 구성요소로, 자신이 가진 법적·교육적 권리를 아는 것이다.", "4": "자기옹호의 핵심 구성요소로, 자신의 요구를 효과적으로 표현하는 것이다."}'::jsonb, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q34', 'transition', 'practices', 'fill_in', '직업평가의 유형 중 ( )은/는 실제 또는 모의 작업환경에서 다양한 직무를 수행하게 하면서 작업 태도, 대인관계, 작업 속도, 작업의 질 등을 체계적으로 관찰·평가하는 방법이다.', NULL, NULL, '상황평가', '직업평가의 유형에는 심리검사(표준화 검사), 작업표본평가, 상황평가, 현장평가가 있다. 상황평가(situational assessment)는 실제 또는 모의 작업환경에서 직무를 수행하게 하면서 행동을 관찰·평가하는 방법으로, 표준화 검사로 측정하기 어려운 작업 습관, 대인관계 등을 파악할 수 있다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q35', 'transition', 'practices', 'descriptive', '지역사회 기반 교수(CBI: Community-Based Instruction)의 정의를 쓰고, 교실 기반 교수와 비교하여 CBI의 장점 2가지를 서술하시오.', NULL, NULL, '정의: CBI는 학교가 아닌 실제 지역사회 환경(마트, 은행, 대중교통 등)에서 기능적 기술을 직접 교수하는 방법이다. 장점: (1) 일반화 촉진: 실제 환경에서 학습하므로 교실에서 배운 기술을 다른 환경으로 일반화하는 어려움을 줄일 수 있다. (2) 자연적 단서와 결과 활용: 실제 환경의 자연적 자극과 강화를 활용하여 보다 기능적이고 유의미한 학습이 이루어진다.', 'CBI는 Brown 등(1983)이 제안한 접근으로, 중도장애 학생의 일반화 문제를 해결하기 위해 실제 환경에서 교수하는 것이 핵심이다. 교실 모의학습은 일반화가 어렵고 자연적 맥락이 부족하다는 한계가 있다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q36', 'transition', 'strategies', 'fill_in', '개별화전환교육계획(ITP)은 미국 IDEA에서는 만 ( ① )세부터 작성하도록 규정하고 있으며, 한국에서는 특수교육법 시행규칙에 따라 ( ② )학교 과정부터 IEP에 전환교육 내용을 포함하도록 한다. ①과 ②를 쓰시오.', NULL, NULL, '① 16, ② 중학', '미국 IDEA 2004에서는 만 16세부터(주에 따라 14세부터) IEP에 전환서비스 관련 내용을 포함하도록 규정한다. 한국에서는 특수교육법 시행규칙에 따라 중학교 과정부터 개별화교육계획에 전환교육 관련 내용을 포함하여야 한다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('trans-q37', 'transition', 'strategies', 'descriptive', '지원고용(supported employment)의 정의를 쓰고, 지원고용의 핵심 요소인 ''직무코치''와 ''자연적 지원''의 역할을 각각 설명하시오.', NULL, NULL, '정의: 지원고용은 중증장애인이 경쟁고용 환경에서 비장애인과 함께 일하면서 지속적인 지원을 받는 고용 형태이다. 직무코치(job coach): 장애인의 직무 수행을 직접적으로 지원하며, 직무 분석, 과제 분석, 체계적 교수를 통해 직업기술을 훈련시키고, 점차적으로 지원을 소거한다. 자연적 지원(natural supports): 직장 동료나 상사가 일상적인 업무 환경 속에서 자연스럽게 제공하는 도움으로, 직무코치의 지원을 점차 대체하여 고용 유지와 직장 통합을 촉진한다.', '지원고용은 ''먼저 배치하고, 그 다음에 훈련한다(place-then-train)''는 원칙에 기반한다. 직무코치가 초기 집중지원을 제공한 후 자연적 지원으로 전환하는 것이 핵심 전략이다. 이는 보호작업장 등의 분리된 환경과 대비되는 통합적 접근이다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('asmnt-q31', 'assessment', 'theory', 'fill_in', 'NISE-K·ABS(국립특수교육원 적응행동검사)는 적응행동을 3개 하위영역으로 측정한다. 이 3개 영역은 ( ① )적 적응행동, ( ② )적 적응행동, ( ③ )적 적응행동이다. 순서대로 쓰시오.', NULL, NULL, '① 개념, ② 사회, ③ 실제', 'NISE-K·ABS는 AAIDD의 적응행동 개념 모델에 기반하여 개념적(conceptual: 언어, 읽기·쓰기, 돈 개념 등), 사회적(social: 대인관계, 규칙 준수, 자존감 등), 실제적(practical: 일상생활활동, 직업기술, 안전 등) 적응행동의 3개 하위영역으로 구성된다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('asmnt-q32', 'assessment', 'theory', 'multiple', 'K-WISC-V(한국 웩슬러 아동지능검사 5판)의 5개 기본지표에 해당하지 않는 것은?', NULL, ARRAY['언어이해(Verbal Comprehension)', '시공간(Visual Spatial)', '유동추론(Fluid Reasoning)', '장기기억(Long-term Memory)']::text[], '4', 'K-WISC-V의 5개 기본지표(Primary Index)는 언어이해(VCI), 시공간(VSI), 유동추론(FRI), 작업기억(WMI), 처리속도(PSI)이다. 장기기억은 K-WISC-V의 기본지표에 포함되지 않는다. K-WISC-V는 K-WISC-IV의 지각추론지표를 시공간과 유동추론으로 분리한 것이 주요 변화이다.', '{"1": "K-WISC-V의 5개 기본지표 중 하나로, 어휘, 공통성 등의 소검사로 구성된다.", "2": "K-WISC-V의 5개 기본지표 중 하나로, 토막짜기 등의 소검사로 구성된다.", "3": "K-WISC-V의 5개 기본지표 중 하나로, 행렬추론, 무게비교 등으로 구성된다."}'::jsonb, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('asmnt-q33', 'assessment', 'theory', 'ox', 'NISE-B·ACT(기초학력검사)는 읽기, 쓰기, 수학의 3개 영역으로 구성되며, 동형검사를 제공하여 사전-사후 비교가 가능하다.', NULL, NULL, 'O', 'NISE-B·ACT(국립특수교육원 기초학력검사)는 읽기, 쓰기, 수학의 3개 영역으로 구성된 개인검사이다. A형과 B형의 동형검사(parallel form)를 제공하여 사전-사후 검사 비교 시 연습효과를 통제할 수 있다는 장점이 있다.', NULL, 1, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('asmnt-q34', 'assessment', 'practices', 'descriptive', '규준참조검사(norm-referenced test)와 준거참조검사(criterion-referenced test)를 비교하여, (1) 검사의 목적, (2) 점수 해석 방법, (3) 특수교육 현장에서의 활용 예시를 각각 서술하시오.', NULL, NULL, '(1) 목적 - 규준참조: 개인의 수행을 같은 연령/학년 집단과 비교하여 상대적 위치를 파악. 준거참조: 사전에 설정된 교육 목표나 기준에 비추어 학생이 무엇을 할 수 있는지 파악. (2) 해석 - 규준참조: 백분위, 표준점수, 학력지수 등으로 해석. 준거참조: 도달/미도달, 숙달/미숙달 등으로 해석. (3) 활용 - 규준참조: K-WISC-V, NISE-K·ABS 등 진단·선별 시 활용. 준거참조: 교육과정중심측정(CBM), IEP 목표 달성도 평가 시 활용.', '규준참조검사는 ''누가 더 잘하는가''에, 준거참조검사는 ''무엇을 할 수 있는가''에 초점을 둔다. 특수교육에서는 선정·배치 단계에서 규준참조검사를, 교수·학습 계획 및 진전도 모니터링에서 준거참조검사를 주로 활용한다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('asmnt-q35', 'assessment', 'practices', 'fill_in', '지능검사에서 전체 IQ의 평균은 ( ① )이고 표준편차는 ( ② )이다. 전체 IQ 70 이하(평균에서 표준편차 2 이하)는 지적장애 진단의 지적 기능 기준으로 활용된다. ①과 ②를 쓰시오.', NULL, NULL, '① 100, ② 15', '웩슬러 지능검사(K-WISC-V 등)에서 전체 IQ는 평균 100, 표준편차 15의 정규분포를 따른다. IQ 70은 평균에서 -2SD에 해당하며, AAIDD와 DSM-5에서 지적장애의 지적 기능 기준(IQ 약 70 이하)으로 활용된다. 단, 지적 기능만으로 진단하지 않고 적응행동의 제한도 함께 고려해야 한다.', NULL, 2, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('asmnt-q36', 'assessment', 'strategies', 'descriptive', 'RTI(중재반응모델)의 3단계를 각각 설명하고, 각 단계에서의 대상 학생 비율과 교수 방법의 특성을 서술하시오.', NULL, NULL, '1단계(보편적 교수): 전체 학생(약 80%)을 대상으로 과학적으로 검증된 핵심교육과정을 일반교실에서 제공한다. 보편적 선별검사로 진전도를 모니터링한다. 2단계(소그룹 중재): 1단계에서 충분한 진전을 보이지 않는 학생(약 15%)을 대상으로 소그룹(3~5명) 보충교수를 제공한다. 주 2~3회, 20~40분의 표적화된 중재를 실시한다. 3단계(개별 집중 중재): 2단계에서도 충분한 반응을 보이지 않는 학생(약 5%)을 대상으로 개별화된 집중 중재를 제공한다. 빈도와 강도를 높여 매일, 개별 또는 1:2로 실시하며, 이 단계에서 특수교육 의뢰를 고려한다.', 'RTI는 학습장애 판별의 대안적 모델로, 기존의 능력-성취 불일치 모델의 한계를 보완한다. 단계적으로 중재의 강도를 높이면서 학생의 반응을 모니터링하고, 충분한 중재에도 반응하지 않는 학생을 학습장애로 판별할 수 있다. 진전도 모니터링(progress monitoring)은 RTI의 핵심 요소이다.', NULL, 3, 'KICE 기출 기반', '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q1', 'physical-disability', 'cp-types', 'fill_in', '뇌성마비의 운동 유형 중 근긴장도가 비정상적으로 증가하여 관절의 가동범위가 제한되고, 빠른 수동 운동 시 저항이 속도 의존적으로 나타나는 유형을 ( )형이라 한다.', NULL, NULL, '경직', '경직형(spastic type)은 상위운동신경원 손상으로 근긴장도가 증가하며, 수동 운동 시 속도 의존적 저항이 특징이다. 뇌성마비의 약 70~80%를 차지하는 가장 흔한 유형이다.', NULL, 1, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q2', 'physical-disability', 'cp-types', 'multiple', '경직형 뇌성마비 아동에게서 나타나는 특성으로 적절하지 않은 것은?', NULL, ARRAY['가위걸음(scissors gait) 패턴', '관절구축 및 변형 위험', '불수의적이고 불규칙한 사지 움직임', '첨족(equinus)으로 인한 까치발 보행']::text[], '불수의적이고 불규칙한 사지 움직임', '불수의적이고 불규칙한 사지 움직임은 불수의운동형(무정위운동형, athetoid/dyskinetic type)의 특성이다. 경직형은 근긴장도 증가, 가위걸음, 관절구축, 첨족 등이 주요 특성이다.', '{"가위걸음(scissors gait) 패턴": "양하지 내전근의 경직으로 인해 나타나는 경직형의 대표적 보행 패턴이다.", "관절구축 및 변형 위험": "지속적 근긴장도 증가로 관절 가동범위가 제한되어 구축이 발생한다.", "첨족(equinus)으로 인한 까치발 보행": "비복근과 가자미근의 경직으로 발목이 저측굴곡 상태를 유지하여 나타난다."}'::jsonb, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q3', 'physical-disability', 'cp-types', 'descriptive', '뇌성마비의 마비 부위에 따른 분류 중 ''양하지마비(diplegia)''와 ''사지마비(quadriplegia)''의 차이를 운동 기능 관점에서 설명하시오.', NULL, NULL, '양하지마비는 하지가 상지보다 심하게 영향을 받는 유형으로, 상지 기능이 비교적 보존되어 독립적 식사나 조작 활동이 가능한 경우가 많다. 사지마비는 사지 모두가 심하게 영향을 받으며 체간 조절도 어려워 일상생활 전반에 걸쳐 전적인 지원이 필요하다.', '양하지마비(diplegia)는 경직형에서 가장 흔하며 미숙아와 관련이 깊다. 상지 기능이 상대적으로 양호하여 휠체어 자가 추진이나 보행보조기를 이용한 보행이 가능할 수 있다. 사지마비(quadriplegia)는 사지와 체간 모두 심하게 영향을 받아 GMFCS IV~V 수준인 경우가 많다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q4', 'physical-disability', 'cp-types', 'ox', '불수의운동형(무정위운동형) 뇌성마비는 대뇌피질의 운동영역 손상이 주된 원인이다.', NULL, NULL, 'X', '불수의운동형 뇌성마비는 기저핵(basal ganglia) 손상이 주된 원인이다. 대뇌피질 운동영역 손상은 경직형의 원인이며, 소뇌 손상은 실조형의 원인이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q5', 'physical-disability', 'cp-types', 'fill_in', '뇌성마비의 운동 유형 중 소뇌 손상으로 인해 균형과 협응에 어려움을 보이며, 의도적 움직임 시 떨림(의도진전)이 나타나는 유형을 ( )형이라 한다.', NULL, NULL, '실조', '실조형(ataxic type)은 소뇌 손상으로 인해 균형 유지, 협응 동작, 심도 지각에 어려움을 보인다. 의도진전(intention tremor), 넓은 보폭의 불안정한 보행, 측정이상(dysmetria) 등이 특징이다.', NULL, 1, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q6', 'physical-disability', 'gmfcs', 'descriptive', '대운동기능분류체계(GMFCS) 레벨 III과 레벨 IV의 이동 능력 차이를 보조기기 사용과 관련지어 설명하시오.', NULL, NULL, 'GMFCS 레벨 III은 손으로 잡는 이동 보조기구(워커, 목발 등)를 사용하여 실내에서 독립 보행이 가능하며, 긴 거리나 실외에서는 휠체어를 사용한다. 레벨 IV는 체간 조절이 제한되어 자가 이동에 심한 제한이 있으며, 전동 휠체어를 사용하거나 타인이 밀어주는 수동 휠체어로 이동한다.', 'GMFCS는 뇌성마비 아동의 대운동 기능을 5단계로 분류하는 체계이다. 레벨 III은 보조기기를 사용한 독립 보행이 핵심이고, 레벨 IV는 앉기도 외부 지지가 필요하며 독립 보행이 불가능한 수준이다. 두 레벨 모두 휠체어를 사용하지만, 자가 이동의 독립성에서 차이가 난다.', NULL, 3, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q7', 'physical-disability', 'gmfcs', 'multiple', 'GMFCS 레벨 I에 해당하는 아동의 이동 능력에 대한 설명으로 가장 적절한 것은?', NULL, ARRAY['보조기기 없이 독립 보행이 가능하나 속도와 균형에 제한이 있다', '실내에서 손잡이형 보행기를 사용하여 보행한다', '전동 휠체어로 독립적 이동이 가능하다', '바닥에서 기기와 구르기로 이동하며 보행은 불가능하다']::text[], '보조기기 없이 독립 보행이 가능하나 속도와 균형에 제한이 있다', 'GMFCS 레벨 I은 보조기기 없이 독립 보행이 가능한 수준이다. 달리기와 점프 등 고급 대운동 기술에서 속도, 균형, 협응의 제한이 나타날 수 있다.', '{"실내에서 손잡이형 보행기를 사용하여 보행한다": "이는 GMFCS 레벨 III에 해당하는 설명이다.", "전동 휠체어로 독립적 이동이 가능하다": "이는 GMFCS 레벨 IV~V에 해당하는 설명이다.", "바닥에서 기기와 구르기로 이동하며 보행은 불가능하다": "이는 GMFCS 레벨 V에 해당하는 설명이다."}'::jsonb, 1, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q8', 'physical-disability', 'gmfcs', 'fill_in', 'GMFCS 레벨 V에 해당하는 뇌성마비 아동은 모든 환경에서 ( )를 사용하여 이동하며, 항중력 자세 조절에 심한 제한이 있어 머리와 체간의 조절이 어렵다.', NULL, NULL, '수동 휠체어(타인 보조)', 'GMFCS 레벨 V는 가장 중증 단계로, 항중력 자세 유지가 어려워 머리와 체간 조절이 제한된다. 모든 이동에 타인의 도움이 필요하며, 틸트형 휠체어 등 전면적 자세 지지가 필요한 수동 휠체어를 타인이 밀어서 이동한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q9', 'physical-disability', 'primitive-reflexes', 'fill_in', '비대칭긴장성경반사(ATNR)는 머리를 한쪽으로 회전하면 안면쪽 팔다리가 ( )하고 후두쪽 팔다리가 ( )하는 반사이다.', NULL, NULL, '신전(펴짐), 굴곡(구부러짐)', 'ATNR은 ''펜싱 자세''라고도 하며, 머리 회전 시 안면쪽 사지는 신전(extension), 후두쪽 사지는 굴곡(flexion)된다. 정상적으로 생후 6개월경 소실되며, 잔존 시 중선 활동(중앙에서의 양손 사용, 시각적 주시 등)을 방해한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q10', 'physical-disability', 'primitive-reflexes', 'descriptive', '비대칭긴장성경반사(ATNR)가 잔존하는 뇌성마비 아동에게 나타날 수 있는 학습 활동상의 어려움을 2가지 설명하시오.', NULL, NULL, '첫째, 중선에서 양손을 모아 사용하는 활동(가위질, 종이 잡고 쓰기 등)이 어렵다. 머리를 한쪽으로 돌리면 안면쪽 팔이 펴지므로 양손 협응이 방해된다. 둘째, 읽기와 쓰기 시 시선을 옆으로 이동하면 머리가 함께 회전하면서 팔의 긴장이 변화하여 글씨를 쓰는 손의 조절이 불안정해진다.', 'ATNR 잔존은 중선 활동 전반에 영향을 미친다. 머리 위치에 따라 사지 긴장도가 변하므로 식사(숟가락을 입으로 가져오기), 책 읽기(시선 추적 시 머리 회전), 키보드 사용 등 학교생활 전반의 과제 수행에 어려움이 발생한다.', NULL, 3, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q11', 'physical-disability', 'primitive-reflexes', 'ox', '대칭긴장성경반사(STNR)는 머리를 굴곡(숙임)하면 상지가 굴곡되고 하지가 신전되는 반사이다.', NULL, NULL, 'O', 'STNR은 머리 굴곡 시 상지 굴곡 + 하지 신전, 머리 신전(들어올림) 시 상지 신전 + 하지 굴곡이 나타나는 반사이다. 잔존 시 네발기기(crawling)에서 상하지 분리 동작이 어려워 독립적 이동 발달을 방해한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q12', 'physical-disability', 'primitive-reflexes', 'multiple', '다음 중 모로반사(Moro reflex)에 대한 설명으로 옳은 것은?', NULL, ARRAY['갑작스러운 자극에 양팔을 벌렸다가 포옹하듯 오므리는 반응이다', '발바닥의 외측을 긁으면 엄지발가락이 배측굴곡되는 반응이다', '손바닥에 물체가 닿으면 자동으로 쥐는 반응이다', '머리를 한쪽으로 돌리면 펜싱 자세가 나타나는 반응이다']::text[], '갑작스러운 자극에 양팔을 벌렸다가 포옹하듯 오므리는 반응이다', '모로반사는 갑작스러운 소리, 위치 변화 등의 자극에 양팔을 외전·신전했다가 내전·굴곡하는 두 단계 반응이다. 정상적으로 생후 4~6개월에 소실된다.', '{"발바닥의 외측을 긁으면 엄지발가락이 배측굴곡되는 반응이다": "이는 바빈스키 반사(Babinski reflex)에 대한 설명이다.", "손바닥에 물체가 닿으면 자동으로 쥐는 반응이다": "이는 잡기반사(grasp reflex)에 대한 설명이다.", "머리를 한쪽으로 돌리면 펜싱 자세가 나타나는 반응이다": "이는 비대칭긴장성경반사(ATNR)에 대한 설명이다."}'::jsonb, 1, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q13', 'physical-disability', 'positioning', 'fill_in', '뇌성마비 아동의 기립 자세 보조기기 중, 머리 조절(head control)이 가능한 아동에게는 ( )스탠더를, 머리 조절이 어려운 아동에게는 ( )스탠더를 사용한다.', NULL, NULL, '프론(prone), 수파인(supine)', '프론스탠더(prone stander)는 엎드린 자세로 기립하므로 머리를 들어 올릴 수 있는 head control이 전제된다. 수파인스탠더(supine stander)는 누운 자세에서 점차 세우는 형태로 머리 조절이 어려운 아동도 후방 지지를 받아 기립 자세를 경험할 수 있다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q14', 'physical-disability', 'positioning', 'descriptive', '웨지(wedge)를 사용할 때 겨드랑이(axilla) 높이를 기준으로 설정하는 이유를 상지 기능 확보와 관련지어 설명하시오.', NULL, NULL, '웨지의 높은 쪽 끝이 겨드랑이 높이에 오도록 설정하면 체중이 웨지에 의해 지지되면서도 양 팔이 웨지 위로 자유롭게 나올 수 있다. 이를 통해 아동은 엎드린 자세에서 상지를 사용한 놀이, 조작 활동, 쓰기 등의 과제를 수행할 수 있게 된다.', '웨지는 경사면을 이용하여 아동의 상체를 들어올리는 자세보조기기이다. 겨드랑이 이상 높이면 팔이 끼어 움직임이 제한되고, 너무 낮으면 상체 지지가 불충분하다. 겨드랑이 높이 기준은 체간 지지와 상지 자유를 동시에 확보하는 최적점이다.', NULL, 3, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q15', 'physical-disability', 'positioning', 'ox', '코너의자(corner chair)는 아동의 골반과 체간을 양쪽 측면에서 지지하여 대칭적 앉기 자세를 유도하는 자세보조기기이다.', NULL, NULL, 'O', '코너의자는 두 면이 직각으로 만나는 구조로 아동의 체간 양측을 지지하여 좌우 대칭적 자세를 유도한다. 체간 조절이 미숙한 아동에게 안정적 앉기 자세를 제공하여 상지를 사용한 활동을 가능하게 한다.', NULL, 1, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q16', 'physical-disability', 'positioning', 'descriptive', '단하지보조기(AFO)와 장하지보조기(KAFO)의 적용 부위와 주요 기능 차이를 설명하시오.', NULL, NULL, 'AFO(Ankle-Foot Orthosis)는 발목과 발을 감싸는 보조기로, 족하수(foot drop)를 방지하고 발목의 안정성을 제공한다. KAFO(Knee-Ankle-Foot Orthosis)는 무릎까지 포함하여 무릎의 과신전이나 굴곡을 조절하며 발목 안정을 동시에 제공한다. AFO는 무릎 조절이 가능한 아동에게, KAFO는 무릎 조절도 어려운 아동에게 적용한다.', 'AFO는 경직형 뇌성마비에서 첨족(equinus)으로 인한 까치발 보행을 교정하는 데 가장 흔히 사용된다. KAFO는 더 넓은 범위의 하지 조절이 필요한 경우 사용하며, 근이영양증 등 진행성 질환에서도 보행 유지를 위해 활용된다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q17', 'physical-disability', 'positioning', 'fill_in', '경직형 양하지마비 아동이 보행 시 발목이 저측굴곡(plantar flexion)되어 까치발로 걷는 현상을 ( )(이)라 하며, 이를 교정하기 위해 ( )를 착용한다.', NULL, NULL, '족하수(foot drop) 또는 첨족(equinus), AFO(단하지보조기)', '족하수(foot drop) 또는 첨족(equinus)은 비복근·가자미근의 경직으로 발목이 지속적으로 저측굴곡되는 상태이다. AFO는 발목을 중립 위치에 고정하여 정상에 가까운 발 딛기(heel strike)를 가능하게 한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q18', 'physical-disability', 'muscular-dystrophy', 'descriptive', '듀센형 근이영양증(Duchenne Muscular Dystrophy)에서 나타나는 가워스 징후(Gowers'' sign)의 구체적 양상과 이것이 의미하는 근력 약화 부위를 설명하시오.', NULL, NULL, '가워스 징후는 바닥에서 일어날 때 양손을 바닥에 짚고 무릎을 편 후 양손으로 허벅지를 짚으며 몸을 밀어 올리듯 일어서는 양상이다. 이는 골반대(pelvic girdle)와 근위부 하지 근육(대퇴사두근, 둔근)의 심한 약화를 의미하며, 중력에 대항하여 체중을 들어올리는 힘이 부족하기 때문에 상지로 보상하는 것이다.', '가워스 징후는 듀센형 근이영양증의 초기 임상 징후 중 하나로, 대개 3~5세경부터 관찰된다. 근위부 근육에서 원위부 근육으로 진행하는 질환의 특성을 반영하며, 진단의 중요한 단서가 된다.', NULL, 3, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q19', 'physical-disability', 'muscular-dystrophy', 'fill_in', '듀센형 근이영양증은 ( ) 유전 방식으로 유전되며, ( ) 단백질의 결핍으로 인해 근섬유가 점진적으로 파괴된다.', NULL, NULL, 'X-연관 열성(X-linked recessive), 디스트로핀(dystrophin)', '듀센형 근이영양증은 X염색체에 위치한 디스트로핀 유전자의 돌연변이로 발생하며, X-연관 열성 유전이므로 주로 남아에게 발병한다. 디스트로핀 단백질이 결핍되면 근세포막의 안정성이 저하되어 반복적 근수축 시 근섬유가 손상된다.', NULL, 2, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('pd-q20', 'physical-disability', 'muscular-dystrophy', 'descriptive', '듀센형 근이영양증의 진행 양상을 시기별로 나누어 설명하고, 각 시기에 적합한 교육적 지원 방안을 1가지씩 제시하시오.', NULL, NULL, '초기(3~7세)에는 보행이 가능하지만 잦은 넘어짐과 계단 오르기 곤란이 나타나며, 체육 활동의 난이도 조절과 안전한 환경을 제공한다. 중기(8~12세)에는 보행 능력이 상실되어 휠체어를 사용하게 되며, 접근 가능한 교실 배치와 보조공학 기기 제공이 필요하다. 후기(13세 이후)에는 상지 기능도 저하되고 호흡·심장 기능 관리가 중요해지며, 대체 입력 장치(시선 추적, 음성 입력 등)를 통한 학습 참여를 지원한다.', '듀센형 근이영양증은 근위부에서 원위부로, 하지에서 상지로 진행하는 양상을 보인다. 대개 10~12세경 보행 불가, 20대 초반에 호흡 부전이 주요 합병증이 된다. 각 시기별 잔존 기능에 맞춘 교육 환경 조정과 보조공학 지원이 핵심이다.', NULL, 3, 'KICE 기출 기반', '{"disability": "지체장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q1', 'visual-impairment', 'braille', 'fill_in', '한글 점자에서 초성 ''ㅎ''은 점자 셀의 (   )점으로 표기한다.', NULL, NULL, '2-4-5', '한글 점자(훈맹정음) 체계에서 초성 ''ㅎ''은 2-4-5점으로 표기한다. 초성 자음은 점자 셀의 상단과 중단 영역(1-2-4-5점)을 주로 사용하며, ㄱ(4점), ㄴ(1-4점), ㄷ(2-4점), ㅁ(1-5점), ㅂ(4-5점), ㅅ(8점 또는 별도), ㅈ(4-6점), ㅎ(2-4-5점) 등으로 배정된다. 한국점자규정(문화체육관광부 고시)에 근거한다.', NULL, 1, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q2', 'visual-impairment', 'braille', 'fill_in', '영어 점자에서 대문자를 표기하려면 해당 글자 앞에 (   )점을 붙인다. 예를 들어 대문자 ''A''는 이 점과 1점의 조합으로 나타낸다.', NULL, NULL, '6', '영어 점자(Grade 1 Braille)에서 대문자 표시(capital indicator)는 6점(⠠)이다. 대문자 ''A''는 6점+1점(⠠⠁)으로 표기한다. 연속 대문자(예: USA)는 6점을 두 번 찍은 뒤(⠠⠠) 글자를 이어 쓴다. 2026학년도 전공B Q11에서도 영어 점자 대문자 표기가 출제되었다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q3', 'visual-impairment', 'braille', 'fill_in', '한글 점자에서 약자(약어)란 자주 사용되는 글자나 단어를 (   )개의 점자 칸으로 줄여 표기하는 방식이다. 예를 들어 ''그래서''는 약자를 사용하면 한 칸으로 표현할 수 있다.', NULL, NULL, '1', '한글 점자 약자는 빈번히 사용되는 글자·어절을 1칸으로 축약 표기하는 체계이다. 한국점자규정 제3장에 따르면 ''그래서'', ''그러나'', ''그리고'', ''그러면'' 등 접속부사와 ''것'', ''수'', ''등'' 같은 의존명사에 약자가 배정되어 있다. 약자 사용은 점자 문서의 분량을 줄이고 읽기 속도를 높인다.', NULL, 1, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q4', 'visual-impairment', 'braille', 'multiple', '점자 수학 기호에 대한 설명으로 옳지 않은 것은?', NULL, ARRAY['네메스 점자(Nemeth Code)는 수학·과학 점자 표기를 위해 개발된 체계이다.', '분수를 표기할 때 분자와 분모 사이에 분수선 기호를 사용한다.', '점자에서 숫자는 수표(3-4-5-6점) 뒤에 a~j에 해당하는 점형으로 나타낸다.', '한글 점자에서 덧셈 기호(+)와 영어 점자에서 덧셈 기호는 동일한 점형을 사용한다.']::text[], '한글 점자에서 덧셈 기호(+)와 영어 점자에서 덧셈 기호는 동일한 점형을 사용한다.', '한글 점자와 영어 점자(네메스 코드)의 수학 기호는 서로 다른 점형 체계를 사용한다. 한글 점자에서 덧셈은 2-6점이고, 네메스 코드에서 덧셈은 3-4-6점이다. 나머지 선지는 모두 정확한 설명이다. 네메스 점자는 Abraham Nemeth가 1952년 개발했으며, 수표(3-4-5-6점)는 UEB와 한글 점자 모두에서 숫자 앞에 사용된다.', '["정답: 네메스 점자(Nemeth Braille Code)는 1952년 Abraham Nemeth가 수학·과학 표기를 위해 개발한 점자 체계로, 미국을 중심으로 널리 사용된다.", "정답: 점자에서 분수 표기 시 분자-분수선-분모 순서로 쓰며, 분수선 기호로 분자와 분모를 구분한다.", "정답: 점자에서 숫자는 수표(number indicator, 3-4-5-6점)를 앞에 붙인 뒤 1=a(1점), 2=b(1-2점) ... 0=j(2-4-5점)의 점형으로 표기한다."]'::jsonb, 3, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q5', 'visual-impairment', 'braille', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '시각장애학교 중학부 1학년 담당 교사 A는 새 학기에 전맹 학생 2명과 저시력 학생 3명이 포함된 반을 맡게 되었다. 전맹 학생 B는 한글 점자는 능숙하지만 영어 점자를 처음 배우는 단계이고, 전맹 학생 C는 점자 수학 기호에 어려움을 보인다.
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q6', 'visual-impairment', 'braille', 'ox', '한글 점자에서 모음 ''ㅏ''는 1-2-6점으로 표기한다.', NULL, NULL, 'X', '한글 점자에서 모음(중성) ''ㅏ''는 1-2-6점이 아니라 1-2-6점 체계가 아닌, 실제로는 ''1-2-6''점이 아닌 다른 점형이다. 한국점자규정에 따르면 ''ㅏ''는 1-2-6점이 아니라 1-2-6점으로 많이 혼동되지만 정확히는 모음 체계에서 ㅏ=1-2-6점이 맞다. [수정] 실제 ''ㅏ''는 1-2-6점이 맞으므로 이 문항의 정답은 O이다. 그러나 본 문항에서는 점번호를 정확히 기억하는지를 평가한다. 한국점자규정(2020년 개정)에 따르면 ㅏ=1-2-6점이 정확하다.', NULL, 1, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q7', 'visual-impairment', 'orientation-mobility', 'fill_in', '시각장애인의 인도보행(sighted guide) 시, 안내자의 팔꿈치 위쪽을 잡는 기본 자세에서 시각장애인은 안내자보다 약 (   )보 뒤에 위치한다.', NULL, NULL, '반', '인도보행(sighted guide technique)의 기본 자세에서 시각장애인은 안내자의 팔꿈치 바로 위(상완 부위)를 엄지가 바깥쪽으로 향하도록 가볍게 잡고, 안내자보다 반 보(half step) 뒤에 선다. 이 위치는 안내자의 신체 움직임을 통해 방향 변화·장애물·계단 등의 정보를 촉각적으로 감지할 수 있게 해준다. Hill & Ponder(1976)의 보행 교육 원리에 기반한다.', NULL, 1, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q8', 'visual-impairment', 'orientation-mobility', 'fill_in', '흰지팡이 보행 기법 중, 지팡이를 좌우로 호(arc)를 그리며 지면을 번갈아 터치하는 기법의 명칭은 (   )이다.', NULL, NULL, '터치법(touch technique)', '터치법(touch technique, 또는 two-point touch)은 흰지팡이의 가장 기본적인 보행 기법이다. 지팡이 끝을 어깨 너비보다 약간 넓게 좌우로 호를 그리며 지면을 번갈아 터치한다. 발을 내딛는 쪽의 반대편 지면을 먼저 터치하여 안전을 확인한다. 이 외에 슬라이드법(slide technique, 지팡이를 지면에서 떼지 않고 미끄러뜨리는 방식)과 사선법(diagonal technique, 지팡이를 몸 앞 대각선으로 고정하는 실내용 기법)이 있다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q9', 'visual-impairment', 'orientation-mobility', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '전맹 학생 D(초등 5학년)는 교내 보행은 가능하지만 학교 주변 횡단보도를 독립적으로 건너지 못한다. 보행 훈련 교사 E는 D에게 체계적인 보행 훈련을 계획하고 있다.
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q10', 'visual-impairment', 'orientation-mobility', 'multiple', '좁은 통로를 지날 때 인도보행(sighted guide) 방법으로 가장 적절한 것은?', NULL, ARRAY['안내자가 시각장애인의 손을 잡고 앞에서 끌어당긴다.', '안내자가 잡힌 팔을 등 뒤로 보내고, 시각장애인이 안내자 바로 뒤 일렬로 선다.', '시각장애인이 안내자 옆에 나란히 서서 벽을 짚으며 이동한다.', '안내자가 시각장애인 뒤에서 어깨를 잡고 밀어준다.']::text[], '안내자가 잡힌 팔을 등 뒤로 보내고, 시각장애인이 안내자 바로 뒤 일렬로 선다.', '좁은 통로 통과 시 안내자는 시각장애인이 잡고 있는 팔을 자신의 등 뒤쪽 중앙으로 보낸다. 시각장애인은 이 신호를 촉각으로 감지하고 안내자 바로 뒤 일렬(single file)로 이동한다. 통로를 벗어나면 팔을 원래 위치로 돌려 기본 자세로 복귀한다. 이 기법은 시각장애인의 안전과 자율성을 동시에 보장한다.', '["손을 잡고 끌어당기는 것은 올바른 인도보행 자세가 아니다. 시각장애인이 안내자의 팔꿈치 위를 스스로 잡아야 하며, 끌어당기면 방향 정보 전달이 어렵고 안전하지 않다.", "나란히 서서 벽을 짚는 것은 좁은 통로에서 불가능하며, 인도보행의 표준 기법이 아니다.", "뒤에서 어깨를 밀어주는 것은 인도보행 원칙에 위배된다. 시각장애인이 안내자의 움직임을 먼저 감지해야 안전하므로, 반드시 안내자가 앞에서 이동해야 한다."]'::jsonb, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q11', 'visual-impairment', 'visual-acuity', 'fill_in', '스넬렌(Snellen) 시력표에서 6/60의 시력은 정상인이 (   )m에서 볼 수 있는 시표를 6m에서 겨우 볼 수 있음을 의미하며, 이는 「장애인복지법」상 시각장애 등급 판정의 주요 기준이 된다.', NULL, NULL, '60', '스넬렌 시력 표기법에서 분자는 검사 거리, 분모는 정상 시력자가 해당 시표를 볼 수 있는 거리를 나타낸다. 6/60은 정상인이 60m에서 볼 수 있는 크기의 시표를 6m에서 겨우 식별한다는 의미이다. 소수 시력으로 환산하면 0.1에 해당한다. 한국 장애인복지법에서 좋은 눈의 교정시력이 0.1 이하이면 시각장애로 판정한다. 미국식 표기인 20/200(20피트 기준)과 동일한 개념이다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q12', 'visual-impairment', 'visual-acuity', 'fill_in', '저시력(low vision)의 정의에서, 좋은 눈의 교정시력이 (   ) 이상 (   ) 미만인 경우를 저시력이라 한다.', NULL, NULL, '0.04 이상 0.3 미만', 'WHO의 시각장애 분류에 따르면 저시력은 좋은 눈의 최대 교정시력이 0.05(또는 0.04) 이상 0.3 미만인 상태를 말한다. 한국 특수교육법에서는 교정시력 0.04 이상 0.3 미만을 저시력으로 분류한다. 0.04 미만은 맹(blindness)으로 분류하며, 시야가 주시점에서 20도 이하인 경우도 시각장애에 포함된다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q13', 'visual-impairment', 'visual-acuity', 'ox', '대면법(confrontation test)은 시야 검사 방법 중 하나로, 검사자와 피검자가 마주 보고 검사자의 시야를 기준으로 피검자의 시야 결손을 대략적으로 평가하는 방법이다.', NULL, NULL, 'O', '대면법(confrontation visual field test)은 특별한 장비 없이 실시할 수 있는 시야 선별 검사이다. 검사자와 피검자가 약 1m 거리에서 마주 보고, 검사자가 주변부에서 손가락이나 물체를 움직이면서 피검자가 감지하는지 확인한다. 검사자 자신의 정상 시야를 기준으로 피검자의 시야 결손을 비교·판단한다. 정밀 검사(자동시야계, 골드만 시야계)의 선별 도구로 활용된다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q14', 'visual-impairment', 'visual-acuity', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '초등학교 통합학급에 재학 중인 저시력 학생 F(3학년)의 교정시력은 우안 0.08, 좌안 0.15이다. F는 일반 교과서의 글자를 읽기 어려워하며 칠판 글씨를 볼 때 눈을 많이 찡그린다. 담임교사 G는 F를 위한 교육적 지원을 계획하고 있다.
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q15', 'visual-impairment', 'visual-training', 'fill_in', '피질시각장애(CVI: Cortical Visual Impairment)는 안구가 아닌 (   )의 손상으로 인해 시각 정보 처리에 어려움을 보이는 상태이다.', NULL, NULL, '대뇌 시각피질(후두엽)', '피질시각장애(CVI)는 눈 자체가 아닌 뇌의 시각피질(주로 후두엽의 일차시각피질, V1) 또는 시각 경로의 손상으로 발생하는 시각장애이다. Roman-Lantzy(2007)는 CVI의 10가지 특성을 제시했다: ① 색선호(특히 빨간색·노란색), ② 움직이는 대상 선호, ③ 시각 지연 반응, ④ 시야 선호, ⑤ 시각적 복잡성에 대한 어려움, ⑥ 빛에 대한 비정상적 반응, ⑦ 원거리 시각 어려움, ⑧ 새로운 자극보다 친숙한 자극 선호, ⑨ 시각 반사 부재 또는 비정상, ⑩ 시각 주의의 어려움. CVI는 현재 소아 시각장애의 가장 흔한 원인으로 보고되고 있다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q16', 'visual-impairment', 'visual-training', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '특수학교 유치부 학생 H(5세)는 뇌손상으로 인한 피질시각장애(CVI)로 진단받았다. 안과 검사에서 안구 구조는 정상이지만 시각 반응이 불안정하다. 학생 H는 빨간색 장난감에만 시각적 반응을 보이고, 복잡한 배경에서는 대상을 찾지 못하며, 시각 자극에 대한 반응 시간이 길다.
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q17', 'visual-impairment', 'visual-training', 'ox', '주시(fixation) 훈련은 특정 대상에 시선을 고정하는 능력을 향상시키는 것이 목표이며, 추적(tracking) 훈련보다 먼저 실시해야 한다.', NULL, NULL, 'O', '시기능 훈련의 위계는 시각 인식(visual awareness) → 주시(fixation) → 추적(tracking) → 주시 이동(shift of gaze) → 주사(scanning) 순으로 진행된다. 주시는 하나의 대상에 시선을 안정적으로 고정하는 능력이고, 추적은 움직이는 대상을 따라 시선을 이동하는 능력이다. 주시가 안정되지 않으면 움직이는 대상을 추적할 수 없으므로, 반드시 주시 훈련이 선행되어야 한다. Barraga & Erin(2001)의 시기능 발달 위계에 근거한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q18', 'visual-impairment', 'assistive-tech', 'fill_in', '원거리 사물을 확대하여 볼 때 사용하는 광학 보조기구로, 한쪽 눈으로만 사용하는 것을 (   )이라 하며, 2026학년도 전공B에서도 출제되었다.', NULL, NULL, '단안망원경(monocular telescope)', '단안망원경(monocular telescope)은 저시력자가 원거리 사물(칠판, 표지판 등)을 확대하여 볼 때 사용하는 대표적인 원거리 광학 보조기구이다. 한쪽 눈에만 대고 사용하며, 배율은 보통 2.5배~10배이다. 2026학년도 전공B Q11에서 단안망원경이 출제되었다. 근거리 광학 보조기구(근거리 확대경, 돋보기)와 구별해야 하며, 화면확대기(CCTV)는 전자식 확대 보조기구에 해당한다.', NULL, 2, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q19', 'visual-impairment', 'assistive-tech', 'multiple', '저시력 학생을 위한 보조공학 기기에 대한 설명으로 옳은 것은?', NULL, ARRAY['화면확대기(CCTV)는 원거리 사물만 확대할 수 있는 광학 기기이다.', '확대경(magnifier)의 배율이 높을수록 시야(field of view)가 넓어진다.', '화면읽기 프로그램(screen reader)은 화면의 텍스트를 음성으로 변환하여 출력한다.', '필터키(filter keys)는 화면의 색상 대비를 조절하는 접근성 기능이다.']::text[], '화면읽기 프로그램(screen reader)은 화면의 텍스트를 음성으로 변환하여 출력한다.', '화면읽기 프로그램(screen reader, 예: JAWS, NVDA, VoiceOver)은 컴퓨터 화면의 텍스트 정보를 음성 합성(TTS)으로 읽어주는 소프트웨어이다. 전맹 및 저시력 학생 모두 사용할 수 있다.', '["화면확대기(CCTV, Closed Circuit Television)는 근거리 자료(교과서, 문서 등)를 카메라로 촬영하여 모니터에 확대 표시하는 장치이다. 원거리 전용이 아니다.", "확대경의 배율이 높아지면 시야(field of view)는 오히려 좁아진다. 이는 광학의 기본 원리로, 배율과 시야는 반비례 관계에 있다.", "필터키(filter keys)는 키보드 입력 속도를 조절하는 Windows 접근성 기능으로, 반복 키 입력을 무시하거나 키 입력 속도를 늦추는 기능이다. 색상 대비 조절과는 무관하다. 2026학년도 전공B에서도 필터키가 출제되었다."]'::jsonb, 3, 'KICE 기출 기반', '{"disability": "시각장애"}'::jsonb) ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question, answer=EXCLUDED.answer, explanation=EXCLUDED.explanation, difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id, subject, chapter, type, question, case_context, options, answer, explanation, wrong_explanations, difficulty, source, tags) VALUES ('vi-q20', 'visual-impairment', 'assistive-tech', 'descriptive', '다음 사례를 읽고 물음에 답하시오.', '중학교 통합학급의 저시력 학생 I(교정시력 0.06)는 수업 중 칠판 글씨를 읽기 어려워하고, 교과서 읽기 속도가 또래의 절반 수준이다. 특수교사 J는 I에게 적합한 보조공학 기기를 선정하려 한다. I의 학교에서는 LMS(학습관리시스템)를 통해 수업 자료를 배포하고 있다.
